package.preload["engine.mutation"] = function()
-- engine/mutation/init.lua
-- The rewrite engine: replaces a live object definition with a new one.
-- This is the only place in the engine that performs a hot-swap.
-- Supports template-based objects and multi-surface containment preservation.

local mutation = {}

-- mutate(registry, loader, object_id, new_source, templates)
--   -> new_object, nil  |  nil, error_string
--
-- Loads new_source into a fresh table, carries over containment references
-- from the old object (location, container, surface contents), then replaces
-- the registry entry. If `templates` is provided and the new object has a
-- `template` field, resolves it before registration.
function mutation.mutate(reg, ldr, object_id, new_source, templates)
  local old = reg:get(object_id)
  if not old then
    return nil, "mutation: object '" .. tostring(object_id) .. "' not found in registry"
  end

  local new_obj, err = ldr.load_source(new_source)
  if not new_obj then
    return nil, err
  end

  -- Resolve template if present
  if new_obj.template and templates then
    new_obj, err = ldr.resolve_template(new_obj, templates)
    if not new_obj then
      return nil, err
    end
  end

  -- Preserve containment references so the object stays in the world.
  new_obj.location  = old.location
  new_obj.container = old.container

  -- Preserve surface contents across mutations.
  -- If both old and new objects have surfaces, carry contents from matching zones.
  if old.surfaces and new_obj.surfaces then
    for surface_name, old_zone in pairs(old.surfaces) do
      if new_obj.surfaces[surface_name] and old_zone.contents then
        new_obj.surfaces[surface_name].contents = old_zone.contents
      end
    end
  end

  -- If old had root contents and new has root contents, preserve them.
  if old.contents and #old.contents > 0 and not new_obj.surfaces then
    new_obj.contents = old.contents
  end

  reg:register(object_id, new_obj)
  return new_obj, nil
end

return mutation

end

package.preload["engine.parser.context"] = function()
-- engine/parser/context.lua
-- Context Window (Tier 4): Tracks recent interactions so the game remembers
-- what the player just did. Maintains a stack of recently referenced objects,
-- search discoveries, and previous room for "go back" support.
--
-- Ownership: Smithers (UI Engineer) — parser pipeline component.
-- Architecture: Module-level state (same pattern as engine/search/init.lua).
--
-- Integration points:
--   verbs/init.lua   — push() on find_visible, set_previous_room on movement
--   search/init.lua  — push_discovery() when search finds an item
--   loop/init.lua    — resolve() for pronoun and bare-noun fallback

local context_window = {}

---------------------------------------------------------------------------
-- Internal state (volatile, not persisted)
---------------------------------------------------------------------------
local _stack = {}               -- Recent interacted objects (most recent first)
local _max_stack = 5
local _previous_room_id = nil   -- Room ID before last room transition
local _discoveries = {}         -- Objects found via search (most recent first)
local _max_discoveries = 5

---------------------------------------------------------------------------
-- Context stack operations
---------------------------------------------------------------------------

--- Push an object to the context stack (most recent interaction).
--- Deduplicates: if the object is already in the stack, moves it to top.
function context_window.push(obj)
    if not obj or not obj.id then return end
    -- Already at top — skip
    if _stack[1] and _stack[1].id == obj.id then return end
    -- Remove duplicate if present (move to top)
    for i = #_stack, 1, -1 do
        if _stack[i].id == obj.id then
            table.remove(_stack, i)
            break
        end
    end
    table.insert(_stack, 1, obj)
    while #_stack > _max_stack do table.remove(_stack) end
end

--- Push a search discovery to both the discovery list and context stack.
--- Called by search/init.lua when an item is found during search.
function context_window.push_discovery(obj)
    if not obj or not obj.id then return end
    -- Deduplicate in discovery list
    for i = #_discoveries, 1, -1 do
        if _discoveries[i].id == obj.id then
            table.remove(_discoveries, i)
            break
        end
    end
    table.insert(_discoveries, 1, obj)
    while #_discoveries > _max_discoveries do table.remove(_discoveries) end
    -- Also push to main context stack
    context_window.push(obj)
end

--- Get the most recent context object (top of stack).
function context_window.peek()
    return _stack[1]
end

--- Get the most recent search discovery.
function context_window.last_discovery()
    return _discoveries[1]
end

--- Get the full context stack (for debugging/testing).
function context_window.get_stack()
    return _stack
end

--- Get the discovery list (for debugging/testing).
function context_window.get_discoveries()
    return _discoveries
end

---------------------------------------------------------------------------
-- Room history for "go back"
---------------------------------------------------------------------------

--- Record the current room before a room transition.
function context_window.set_previous_room(room_id)
    _previous_room_id = room_id
end

--- Get the previous room ID (for "go back").
function context_window.get_previous_room()
    return _previous_room_id
end

---------------------------------------------------------------------------
-- Resolution: resolve noun references from context
---------------------------------------------------------------------------

--- Resolve a noun reference using the context window.
--- Handles pronouns ("it", "that", "this"), discovery references
--- ("the thing I found"), and returns the resolved object or nil.
function context_window.resolve(noun)
    if not noun then return nil end
    local kw = noun:lower()
        :gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")

    -- Direct pronouns → most recent context object
    if kw == "it" or kw == "that" or kw == "this" or kw == "one" then
        return _stack[1]
    end

    -- BUG-114: "thing I found" / "one I found" / "what I found" etc. → last discovery
    if kw:match("thing%s+i%s+found")
        or kw:match("one%s+i%s+found")
        or kw:match("what%s+i%s+found")
        or kw:match("thing%s+i%s+discovered")
        or kw:match("one%s+i%s+discovered")
        or kw:match("item%s+i%s+found")
        or kw:match("thing%s+i%s+just%s+found")
        or kw:match("one%s+i%s+just%s+found") then
        return _discoveries[1]
    end

    return nil
end

---------------------------------------------------------------------------
-- Reset (for testing)
---------------------------------------------------------------------------

function context_window.reset()
    _stack = {}
    _discoveries = {}
    _previous_room_id = nil
end

return context_window

end

package.preload["engine.parser.embedding_matcher"] = function()
-- engine/parser/embedding_matcher.lua
-- Tier 2 parser: loads the embedding index JSON as a phrase dictionary
-- and matches player input via token-overlap similarity (Jaccard index).
--
-- We can't run GTE-tiny inference in Lua, so the embedding vectors are
-- ignored at runtime here. The phrase TEXT is what we match against.
-- Real vector similarity comes later in the browser via ONNX Runtime Web.

local json = require("engine.parser.json")

local matcher = {}
matcher.__index = matcher

-- Stop words stripped from both input and phrase text before comparison
local STOP_WORDS = {
  ["the"] = true, ["a"] = true, ["an"] = true, ["some"] = true,
  ["to"] = true, ["at"] = true, ["on"] = true, ["in"] = true,
  ["of"] = true, ["my"] = true, ["its"] = true, ["this"] = true,
  ["that"] = true, ["is"] = true, ["it"] = true, ["i"] = true,
  ["and"] = true, ["or"] = true, ["with"] = true, ["for"] = true,
  ["up"] = true, ["down"] = true, ["around"] = true,
}

---------------------------------------------------------------------------
-- Levenshtein edit distance for typo correction
---------------------------------------------------------------------------
local function levenshtein(a, b)
  local la, lb = #a, #b
  if la == 0 then return lb end
  if lb == 0 then return la end
  local matrix = {}
  for i = 0, la do
    matrix[i] = { [0] = i }
  end
  for j = 0, lb do
    matrix[0][j] = j
  end
  for i = 1, la do
    for j = 1, lb do
      local cost = (a:sub(i, i) == b:sub(j, j)) and 0 or 1
      matrix[i][j] = math.min(
        matrix[i - 1][j] + 1,
        matrix[i][j - 1] + 1,
        matrix[i - 1][j - 1] + cost
      )
    end
  end
  return matrix[la][lb]
end

---------------------------------------------------------------------------
-- Typo correction: fix misspelled verbs using known verb set
---------------------------------------------------------------------------
local function correct_typos(tokens, known_verbs)
  if not known_verbs or not next(known_verbs) then return tokens end
  local corrected = {}
  for _, token in ipairs(tokens) do
    if known_verbs[token] then
      corrected[#corrected + 1] = token
    else
      -- Short words (≤4 chars): require exact match only — no fuzzy correction.
      -- A 1-char edit on a 4-char word is 25% change, too aggressive (kick→lick).
      if #token <= 4 then
        corrected[#corrected + 1] = token
      else
        local best_verb, best_dist = nil, 3
        for verb in pairs(known_verbs) do
          if math.abs(#token - #verb) <= 2 then
            local dist = levenshtein(token, verb)
            if dist < best_dist then
              best_dist = dist
              best_verb = verb
            end
          end
        end
        if best_verb then
          corrected[#corrected + 1] = best_verb
        else
          corrected[#corrected + 1] = token
        end
      end
    end
  end
  return corrected
end

---------------------------------------------------------------------------
-- Tokenizer: lowercase, strip punctuation, remove stop words
---------------------------------------------------------------------------
local function tokenize(text)
  local tokens = {}
  local seen = {}
  for word in text:lower():gsub("[^%a%d%-]", " "):gmatch("%S+") do
    if not STOP_WORDS[word] and not seen[word] then
      tokens[#tokens + 1] = word
      seen[word] = true
    end
  end
  return tokens
end

local function token_set(tokens)
  local s = {}
  for _, t in ipairs(tokens) do s[t] = true end
  return s
end

---------------------------------------------------------------------------
-- Similarity: Jaccard index (|A ∩ B| / |A ∪ B|) with substring bonus
---------------------------------------------------------------------------
local function jaccard_with_bonus(input_tokens, phrase_tokens)
  local set_a = token_set(input_tokens)
  local set_b = token_set(phrase_tokens)

  local intersection = 0
  local union_set = {}

  for t in pairs(set_a) do union_set[t] = true end
  for t in pairs(set_b) do union_set[t] = true end

  -- Exact token matches
  for t in pairs(set_a) do
    if set_b[t] then
      intersection = intersection + 1
    end
  end

  -- Substring/prefix bonus: if an input token is a prefix of a phrase token
  -- (or vice versa), count a partial match
  local partial = 0
  for _, a in ipairs(input_tokens) do
    if not set_b[a] then
      for _, b in ipairs(phrase_tokens) do
        if not set_a[b] then
          if a:sub(1, 3) == b:sub(1, 3) and #a >= 3 and #b >= 3 then
            -- Shared 3+ char prefix → partial credit
            local overlap = 0
            for i = 1, math.min(#a, #b) do
              if a:sub(i, i) == b:sub(i, i) then overlap = overlap + 1
              else break end
            end
            partial = partial + (overlap / math.max(#a, #b)) * 0.5
          end
        end
      end
    end
  end

  local union_size = 0
  for _ in pairs(union_set) do union_size = union_size + 1 end

  if union_size == 0 then return 0 end
  return (intersection + partial) / union_size
end

---------------------------------------------------------------------------
-- Constructor
---------------------------------------------------------------------------
function matcher.new(index_path, debug)
  local self = setmetatable({}, matcher)
  self.phrases = {}
  self.loaded = false
  self.diagnostic = debug or false

  local f = io.open(index_path, "r")
  if not f then
    io.stderr:write("[Parser] Warning: embedding index not found: " .. index_path .. "\n")
    return self
  end

  local content = f:read("*a")
  f:close()

  local ok, index = pcall(json.decode, content)
  if not ok then
    io.stderr:write("[Parser] Warning: failed to parse embedding index: " .. tostring(index) .. "\n")
    return self
  end

  -- Build phrase dictionary (we skip the embedding vectors -- Lua doesn't use them)
  for _, entry in ipairs(index.phrases or {}) do
    self.phrases[#self.phrases + 1] = {
      text = entry.text,
      verb = entry.verb,
      noun = entry.noun,
      tokens = tokenize(entry.text),
    }
  end

  -- Build known-verbs set from the index for typo correction
  self.known_verbs = {}
  for _, entry in ipairs(self.phrases) do
    if entry.verb then
      self.known_verbs[entry.verb] = true
    end
  end

  self.loaded = true
  if self.diagnostic then
    io.stderr:write("[Parser] Tier 2 loaded: " .. #self.phrases .. " phrases from index\n")
  end
  return self
end

---------------------------------------------------------------------------
-- match(input_text) -> verb, noun, score, matched_phrase
-- Returns the best-matching phrase's verb+noun with confidence score.
-- Returns nil if no phrases loaded.
---------------------------------------------------------------------------
function matcher:match(input_text)
  if not self.loaded or #self.phrases == 0 then
    return nil, nil, 0, nil
  end

  local input_tokens = tokenize(input_text)
  if #input_tokens == 0 then
    return nil, nil, 0, nil
  end

  -- Apply typo correction against known verbs before matching
  input_tokens = correct_typos(input_tokens, self.known_verbs)

  local best_score = -1
  local best_phrase = nil

  for _, phrase in ipairs(self.phrases) do
    local score = jaccard_with_bonus(input_tokens, phrase.tokens)
    if score > best_score then
      best_score = score
      best_phrase = phrase
    end
  end

  if best_phrase then
    return best_phrase.verb, best_phrase.noun, best_score, best_phrase.text
  end

  return nil, nil, 0, nil
end

return matcher

end

package.preload["engine.parser.fuzzy"] = function()
-- engine/parser/fuzzy.lua
-- Tier 5: Fuzzy Noun Resolution
-- Owned by Smithers (UI Engineer). Pure functions, no side effects.
--
-- Provides fallback noun matching when exact keyword matching fails:
--   1. Material matching: "the wooden thing" → objects with material="wood"
--   2. Property matching: "the heavy one" → match by weight/size
--   3. Partial name match: "that bottle" → "small glass bottle" (unambiguous)
--   4. Typo tolerance: "nighstand" → "nightstand" via Levenshtein distance
--   5. Disambiguation prompt: multiple matches → ask the player
--
-- Only fires when exact matching fails (don't slow down the happy path).

local fuzzy = {}

---------------------------------------------------------------------------
-- Levenshtein edit distance
-- Reuses the algorithm from embedding_matcher.lua for consistency.
---------------------------------------------------------------------------
function fuzzy.levenshtein(a, b)
    local la, lb = #a, #b
    if la == 0 then return lb end
    if lb == 0 then return la end
    local prev = {}
    local curr = {}
    for j = 0, lb do prev[j] = j end
    for i = 1, la do
        curr[0] = i
        for j = 1, lb do
            local cost = (a:sub(i, i) == b:sub(j, j)) and 0 or 1
            curr[j] = math.min(
                prev[j] + 1,
                curr[j - 1] + 1,
                prev[j - 1] + cost
            )
        end
        prev, curr = curr, prev
    end
    return prev[lb]
end

---------------------------------------------------------------------------
-- Typo tolerance thresholds (per D-BUG018: no fuzzy on short words)
-- Short words (≤4): exact only. Medium (5-7): distance ≤2. Long (8+): distance ≤2.
-- Per task spec: "1-2 character difference for short words, 2-3 for longer words"
---------------------------------------------------------------------------
function fuzzy.max_typo_distance(word_len)
    if word_len <= 4 then return 0 end
    if word_len <= 7 then return 2 end
    return 2
end

---------------------------------------------------------------------------
-- Material adjective → material value mapping
---------------------------------------------------------------------------
local MATERIAL_ADJECTIVES = {
    wooden = "wood", wood = "wood",
    metal = "metal", metallic = "metal",
    brass = "brass", bronze = "bronze",
    iron = "iron", steel = "steel",
    glass = "glass", crystal = "crystal",
    stone = "stone", rocky = "stone",
    cloth = "cloth", fabric = "cloth",
    leather = "leather",
    paper = "paper", parchment = "parchment",
    wax = "wax", waxen = "wax",
    ceramic = "ceramic", clay = "ceramic",
    silver = "silver", gold = "gold",
    copper = "copper", tin = "tin",
    bone = "bone",
    rubber = "rubber",
    silk = "silk",
    wool = "wool", woolen = "wool",
    cotton = "cotton",
    linen = "linen",
    velvet = "velvet",
    rope = "rope",
    porcelain = "porcelain",
}

fuzzy.MATERIAL_ADJECTIVES = MATERIAL_ADJECTIVES

---------------------------------------------------------------------------
-- Property adjective → property/comparator mapping
---------------------------------------------------------------------------
local PROPERTY_ADJECTIVES = {
    heavy  = { field = "weight", compare = "high" },
    light  = { field = "weight", compare = "low" },
    big    = { field = "size",   compare = "high" },
    large  = { field = "size",   compare = "high" },
    small  = { field = "size",   compare = "low" },
    tiny   = { field = "size",   compare = "low" },
    little = { field = "size",   compare = "low" },
}

fuzzy.PROPERTY_ADJECTIVES = PROPERTY_ADJECTIVES

---------------------------------------------------------------------------
-- Parse a fuzzy noun phrase into components:
--   "the wooden thing" → { material_adj = "wooden", base_noun = "thing" }
--   "the heavy one"    → { property_adj = "heavy", base_noun = "one" }
--   "that bottle"      → { base_noun = "bottle" }
---------------------------------------------------------------------------
function fuzzy.parse_noun_phrase(noun)
    if not noun or noun == "" then return nil end
    local kw = noun:lower()
        :gsub("^the%s+", "")
        :gsub("^a%s+", "")
        :gsub("^an%s+", "")
        :gsub("^that%s+", "")
        :gsub("^this%s+", "")

    if kw == "" then return nil end

    local result = { raw = kw }

    -- Check for material adjective as first word
    local first, rest = kw:match("^(%S+)%s+(.+)$")
    if first then
        if MATERIAL_ADJECTIVES[first] then
            result.material_adj = first
            result.material_value = MATERIAL_ADJECTIVES[first]
            result.base_noun = rest
            return result
        end
        if PROPERTY_ADJECTIVES[first] then
            result.property_adj = first
            result.property_spec = PROPERTY_ADJECTIVES[first]
            result.base_noun = rest
            return result
        end
    end

    result.base_noun = kw
    return result
end

---------------------------------------------------------------------------
-- Gather all visible objects from context (room + surfaces + hands + bags + worn)
-- Returns flat list of { obj = <table>, loc = <string>, parent = <obj|nil>, surface = <string|nil> }
---------------------------------------------------------------------------
function fuzzy.gather_visible(ctx)
    local results = {}
    local room = ctx.current_room
    local reg = ctx.registry
    local seen = {}

    local function add(obj, loc, parent, surface)
        if obj and not seen[obj.id or tostring(obj)] then
            seen[obj.id or tostring(obj)] = true
            results[#results + 1] = { obj = obj, loc = loc, parent = parent, surface = surface }
        end
    end

    -- Room contents (non-hidden)
    for _, obj_id in ipairs(room.contents or {}) do
        local obj = reg:get(obj_id)
        if obj and not obj.hidden then
            add(obj, "room", nil, nil)
            -- Surface contents
            if obj.surfaces then
                for sname, zone in pairs(obj.surfaces) do
                    if zone.accessible ~= false then
                        for _, item_id in ipairs(zone.contents or {}) do
                            local item = reg:get(item_id)
                            if item then
                                add(item, "surface", obj, sname)
                                -- Nested container contents
                                if item.contents then
                                    for _, inner_id in ipairs(item.contents) do
                                        local inner = reg:get(inner_id)
                                        if inner then add(inner, "container", item, nil) end
                                    end
                                end
                            end
                        end
                    end
                end
            end
            -- Parts
            if obj.parts then
                for part_key, part in pairs(obj.parts) do
                    add(part, "part", obj, part_key)
                end
            end
        end
    end

    -- Player hands
    local player = ctx.player
    for i = 1, 2 do
        local hand = player.hands[i]
        if hand then
            local obj = type(hand) == "table" and hand or reg:get(hand)
            if obj then
                add(obj, "hand", nil, nil)
                -- Bag contents
                if obj.container and obj.contents then
                    for _, item_id in ipairs(obj.contents) do
                        local item = reg:get(item_id)
                        if item then add(item, "bag", obj, nil) end
                    end
                end
                -- Parts of held objects
                if obj.parts then
                    for pk, part in pairs(obj.parts) do
                        add(part, "part", obj, pk)
                    end
                end
            end
        end
    end

    -- Worn items
    for _, worn_id in ipairs(player.worn or {}) do
        local obj = reg:get(worn_id)
        if obj then
            add(obj, "worn", nil, nil)
            if obj.container and obj.contents then
                for _, item_id in ipairs(obj.contents) do
                    local item = reg:get(item_id)
                    if item then add(item, "bag", obj, nil) end
                end
            end
        end
    end

    return results
end

---------------------------------------------------------------------------
-- Build a flat list of matchable strings for an object (name + keywords + id)
---------------------------------------------------------------------------
local function matchable_strings(obj)
    local strings = {}
    if obj.name then strings[#strings + 1] = obj.name:lower() end
    if obj.id then strings[#strings + 1] = obj.id:lower() end
    if type(obj.keywords) == "table" then
        for _, k in ipairs(obj.keywords) do
            strings[#strings + 1] = k:lower()
        end
    end
    return strings
end

---------------------------------------------------------------------------
-- Score a single object against a fuzzy noun phrase.
-- Returns: score (0 = no match, higher = better), match_reason (string)
---------------------------------------------------------------------------
function fuzzy.score_object(obj, parsed)
    if not obj or not parsed then return 0, nil end
    local base = parsed.base_noun or parsed.raw

    -- Generic nouns that match by adjective alone
    local generic_nouns = { thing = true, one = true, object = true, item = true, stuff = true }

    ---------------------------------------------------------------------------
    -- 1. Material matching: "the wooden thing"
    ---------------------------------------------------------------------------
    if parsed.material_value then
        local obj_material = obj.material and obj.material:lower() or nil
        local obj_cats = obj.categories or {}

        local material_match = false
        if obj_material == parsed.material_value then
            material_match = true
        end
        -- Also check categories for material
        if not material_match then
            for _, cat in ipairs(obj_cats) do
                if cat:lower() == parsed.material_value
                    or cat:lower() == parsed.material_adj then
                    material_match = true
                    break
                end
            end
        end

        if material_match then
            if generic_nouns[base] then
                return 3, "material"
            end
            -- Material + partial name
            for _, s in ipairs(matchable_strings(obj)) do
                if s:find(base, 1, true) then
                    return 5, "material+name"
                end
            end
            return 2, "material_only"
        end
        return 0, nil
    end

    ---------------------------------------------------------------------------
    -- 2. Property matching: "the heavy one"
    ---------------------------------------------------------------------------
    if parsed.property_spec then
        local spec = parsed.property_spec
        local val = obj[spec.field]
        if val and type(val) == "number" then
            if generic_nouns[base] then
                return 3, "property"
            end
            -- Property + partial name
            for _, s in ipairs(matchable_strings(obj)) do
                if s:find(base, 1, true) then
                    return 5, "property+name"
                end
            end
            return 0, nil
        end
        return 0, nil
    end

    ---------------------------------------------------------------------------
    -- 3. Partial name match: "bottle" → "small glass bottle"
    -- Requires base noun ≥3 chars to avoid spurious substring matches.
    ---------------------------------------------------------------------------
    if #base >= 3 then
        for _, s in ipairs(matchable_strings(obj)) do
            if s:find(base, 1, true) then
                -- Exact keyword/id match scores highest
                if s == base then return 10, "exact" end
                -- Substring of name or keyword
                return 4, "partial"
            end
        end
    end

    ---------------------------------------------------------------------------
    -- 4. Typo tolerance via Levenshtein distance
    ---------------------------------------------------------------------------
    local max_dist = fuzzy.max_typo_distance(#base)
    if max_dist > 0 then
        local best_dist = max_dist + 1
        for _, s in ipairs(matchable_strings(obj)) do
            -- Compare against each word in multi-word strings too
            for word in s:gmatch("%S+") do
                if math.abs(#word - #base) <= max_dist then
                    local d = fuzzy.levenshtein(base, word)
                    if d < best_dist then best_dist = d end
                end
            end
            -- Also compare against full string for single-word keywords
            if not s:find(" ") and math.abs(#s - #base) <= max_dist then
                local d = fuzzy.levenshtein(base, s)
                if d < best_dist then best_dist = d end
            end
        end
        if best_dist <= max_dist then
            return 3 - best_dist + 1, "typo"
        end
    end

    return 0, nil
end

---------------------------------------------------------------------------
-- Rank visible objects by fuzzy match quality for property comparisons.
-- For "heavy one": pick the highest-weight object among matches.
-- For "light one": pick the lowest-weight object.
---------------------------------------------------------------------------
local function rank_by_property(matches, spec)
    if #matches <= 1 then return matches end
    table.sort(matches, function(a, b)
        local va = a.obj[spec.field] or 0
        local vb = b.obj[spec.field] or 0
        if spec.compare == "high" then return va > vb end
        return va < vb
    end)
    -- If top two have different values, the top one is clearly "the heavy one"
    local top_val = matches[1].obj[spec.field] or 0
    local second_val = matches[2].obj[spec.field] or 0
    if top_val ~= second_val then
        return { matches[1] }
    end
    return matches
end

---------------------------------------------------------------------------
-- resolve(ctx, keyword) -> obj, loc, parent, surface, prompt_text
-- Main entry point. Called as fallback when exact matching fails.
-- Returns:
--   Single match: obj, loc, parent, surface, nil
--   Multiple matches: nil, nil, nil, nil, disambiguation_prompt
--   No match: nil, nil, nil, nil, nil
---------------------------------------------------------------------------
function fuzzy.resolve(ctx, keyword)
    if not keyword or keyword == "" then return nil end

    local parsed = fuzzy.parse_noun_phrase(keyword)
    if not parsed then return nil end

    local visible = fuzzy.gather_visible(ctx)
    if #visible == 0 then return nil end

    -- Score all visible objects
    local scored = {}
    for _, entry in ipairs(visible) do
        local score, reason = fuzzy.score_object(entry.obj, parsed)
        if score > 0 then
            scored[#scored + 1] = {
                obj = entry.obj, loc = entry.loc,
                parent = entry.parent, surface = entry.surface,
                score = score, reason = reason,
            }
        end
    end

    if #scored == 0 then return nil end

    -- Sort by score descending
    table.sort(scored, function(a, b) return a.score > b.score end)

    -- Filter to top-scoring tier
    local top_score = scored[1].score
    local top_matches = {}
    for _, m in ipairs(scored) do
        if m.score == top_score then
            top_matches[#top_matches + 1] = m
        end
    end

    -- Property-based: use ranking to pick best
    if parsed.property_spec and #top_matches > 1 then
        top_matches = rank_by_property(top_matches, parsed.property_spec)
    end

    -- Single unambiguous match
    if #top_matches == 1 then
        local m = top_matches[1]
        return m.obj, m.loc, m.parent, m.surface, nil
    end

    -- Multiple matches → disambiguation prompt (Prime Directive friendly)
    local names = {}
    for _, m in ipairs(top_matches) do
        local name = m.obj.name or m.obj.id or "something"
        names[#names + 1] = name
    end

    local prompt
    if #names == 2 then
        prompt = "Which do you mean: " .. names[1] .. " or " .. names[2] .. "?"
    else
        local parts = {}
        for i, n in ipairs(names) do
            if i == #names then
                parts[#parts + 1] = "or " .. n
            else
                parts[#parts + 1] = n
            end
        end
        prompt = "Which do you mean: " .. table.concat(parts, ", ") .. "?"
    end

    return nil, nil, nil, nil, prompt
end

---------------------------------------------------------------------------
-- correct_typo(keyword, visible_objects) -> corrected_keyword or nil
-- Standalone typo correction: given a keyword and list of visible objects,
-- returns the corrected keyword if a close Levenshtein match is found.
-- Used for providing "Did you mean...?" suggestions.
---------------------------------------------------------------------------
function fuzzy.correct_typo(keyword, visible)
    if not keyword or keyword == "" then return nil end
    local kw = keyword:lower()
    local max_dist = fuzzy.max_typo_distance(#kw)
    if max_dist == 0 then return nil end

    local best_word = nil
    local best_dist = max_dist + 1

    for _, entry in ipairs(visible) do
        for _, s in ipairs(matchable_strings(entry.obj)) do
            for word in s:gmatch("%S+") do
                if math.abs(#word - #kw) <= max_dist then
                    local d = fuzzy.levenshtein(kw, word)
                    if d > 0 and d < best_dist then
                        best_dist = d
                        best_word = word
                    end
                end
            end
        end
    end

    if best_word then return best_word end
    return nil
end

return fuzzy

end

package.preload["engine.parser.goal_planner"] = function()
-- engine/parser/goal_planner.lua
-- Tier 3→6: backward-chaining prerequisite resolver.
-- Fires when a verb+object has unmet tool/capability requirements.
-- Builds a plan of preparatory steps, executes them through Tier 1 dispatch.
--
-- Tier 6: Generalized GOAP — property-based goal matching.
-- Goals are defined by requirement properties (needs_light, needs_key,
-- needs_tool) rather than hardcoded verb chains. The planner walks
-- backwards from the goal, finding objects that provide required properties.
-- Safety limit: MAX_PLAN_DEPTH (7 steps) prevents runaway chains.

local goal_planner = {}
local MAX_DEPTH = 7
-- BUG-090: Maximum plan steps to prevent infinite prerequisite chains
local MAX_PLAN_STEPS = 20
local preprocess = require("engine.parser.preprocess")

-- Tier 6: Presentation module for light-level checks
local pres_ok, presentation = pcall(require, "engine.ui.presentation")
if not pres_ok then presentation = nil end

-- Verb synonyms: verbs that should trigger the same GOAP prerequisite chain
local VERB_SYNONYMS = { burn = "light" }

-- Tier 6: Verbs that require light (room must not be dark)
local LIGHT_VERBS = {
    read = true, write = true,
}

---------------------------------------------------------------------------
-- Helpers: keyword matching (mirrors verbs module)
-- BUG-056: tries singular forms of plural nouns as fallback
---------------------------------------------------------------------------
local function kw_match(obj, kw)
    if not obj then return false end
    kw = kw:lower()
    local candidates = { kw }
    for _, s in ipairs(preprocess.singularize(kw)) do
        candidates[#candidates + 1] = s
    end
    for _, try_kw in ipairs(candidates) do
        if obj.id and obj.id:lower() == try_kw then return true end
        for _, k in ipairs(obj.keywords or {}) do
            if k:lower() == try_kw then return true end
        end
        if obj.name then
            local p = " " .. obj.name:lower() .. " "
            if p:find(" " .. try_kw .. " ", 1, true) then return true end
        end
    end
    return false
end

local function strip_articles(noun)
    return noun:lower():gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
end

--- Comprehensive check: is an object in a terminal/spent/consumed state?
-- Covers _state == "spent", state.terminal, consumable flag, and "useless" category.
local function is_spent_or_terminal(obj)
    if not obj then return true end
    if obj._state == "spent" then return true end
    if obj.consumable == true then return true end
    if obj.states and obj._state then
        local state_data = obj.states[obj._state]
        if state_data and state_data.terminal then return true end
    end
    if obj.categories then
        for _, cat in ipairs(obj.categories) do
            if cat == "useless" then return true end
        end
    end
    return false
end

-- Instance-aware hand accessors for goal planner
local function _gp_hid(hand)
    if type(hand) == "table" then return hand.id end
    return hand
end
local function _gp_hobj(hand, reg)
    if type(hand) == "table" then return hand end
    if type(hand) == "string" then return reg:get(hand) end
    return nil
end

---------------------------------------------------------------------------
-- State queries
---------------------------------------------------------------------------
local function has_tool(ctx, cap)
    local reg = ctx.registry
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _gp_hobj(hand, reg)
            if obj then
                local pt = obj.provides_tool
                if pt == cap then return true end
                if type(pt) == "table" then
                    for _, c in ipairs(pt) do if c == cap then return true end end
                end
            end
            if obj and obj.container and obj.contents then
                for _, cid in ipairs(obj.contents) do
                    local item = reg:get(cid)
                    if item and item.provides_tool == cap then return true end
                end
            end
        end
    end
    for _, id in ipairs(ctx.current_room.contents or {}) do
        local obj = ctx.registry:get(id)
        if obj and obj.provides_tool == cap then return true end
    end
    if cap == "fire_source" and ctx.player.state.has_flame
        and ctx.player.state.has_flame > 0 then
        return true
    end
    return false
end

local function is_held(ctx, obj_id)
    return _gp_hid(ctx.player.hands[1]) == obj_id or _gp_hid(ctx.player.hands[2]) == obj_id
end

---------------------------------------------------------------------------
-- Find all reachable objects matching a keyword
---------------------------------------------------------------------------
local function find_all(ctx, keyword)
    local out = {}
    local reg = ctx.registry
    local kw = strip_articles(keyword)
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _gp_hobj(hand, reg)
            if obj and kw_match(obj, kw) then
                out[#out + 1] = { obj = obj, where = "hand" }
            end
            if obj and obj.container and obj.contents then
                for _, cid in ipairs(obj.contents) do
                    local item = reg:get(cid)
                    if item and kw_match(item, kw) then
                        out[#out + 1] = { obj = item, where = "container",
                            parent = obj, accessible = (obj.accessible ~= false) }
                    end
                end
            end
        end
    end
    for _, id in ipairs(ctx.current_room.contents or {}) do
        local obj = reg:get(id)
        if obj and not obj.hidden and kw_match(obj, kw) then
            out[#out + 1] = { obj = obj, where = "room" }
        end
        if obj and obj.container and obj.contents then
            for _, cid in ipairs(obj.contents) do
                local item = reg:get(cid)
                if item and kw_match(item, kw) then
                    out[#out + 1] = { obj = item, where = "container",
                        parent = obj, accessible = (obj.accessible ~= false) }
                end
            end
        end
        -- Search ALL surfaces (including inaccessible ones for planning)
        if obj and obj.surfaces then
            for _, zone in pairs(obj.surfaces) do
                local zone_ok = (zone.accessible ~= false)
                for _, cid in ipairs(zone.contents or {}) do
                    local item = reg:get(cid)
                    if item and kw_match(item, kw) then
                        out[#out + 1] = { obj = item, where = "surface", parent = obj,
                            surface_accessible = zone_ok }
                    end
                    -- Nested: items inside containers on surfaces
                    if item and item.container and item.contents then
                        for _, inner_id in ipairs(item.contents) do
                            local inner = reg:get(inner_id)
                            if inner and kw_match(inner, kw) then
                                out[#out + 1] = { obj = inner, where = "nested",
                                    parent = item, grandparent = obj,
                                    accessible = (item.accessible ~= false),
                                    surface_accessible = zone_ok }
                            end
                        end
                    end
                end
            end
        end
    end
    return out
end

local function find_property(ctx, prop)
    local reg = ctx.registry
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _gp_hobj(hand, reg)
            if obj and obj[prop] then return obj end
        end
    end
    for _, id in ipairs(ctx.current_room.contents or {}) do
        local obj = reg:get(id)
        if obj and obj[prop] then return obj end
        if obj and obj.surfaces then
            for _, zone in pairs(obj.surfaces) do
                for _, cid in ipairs(zone.contents or {}) do
                    local item = reg:get(cid)
                    if item and item[prop] then return item end
                end
            end
        end
        if obj and obj.container and obj.contents then
            for _, cid in ipairs(obj.contents) do
                local item = reg:get(cid)
                if item and item[prop] then return item end
            end
        end
    end
    return nil
end

---------------------------------------------------------------------------
-- Tier 6: Find objects that can cast light via FSM state transition
-- Returns list of { obj, transition, entry } candidates
---------------------------------------------------------------------------
local function find_lightable(ctx)
    local reg = ctx.registry
    local candidates = {}

    local function check_obj(obj, entry_info)
        if not obj or not obj.states or not obj._state then return end
        if is_spent_or_terminal(obj) then return end
        for state_name, state_data in pairs(obj.states) do
            if type(state_data) == "table" and state_data.casts_light then
                if obj._state ~= state_name then
                    for _, t in ipairs(obj.transitions or {}) do
                        if t.from == obj._state and t.to == state_name
                            and t.trigger ~= "auto" then
                            candidates[#candidates + 1] = {
                                obj = obj, transition = t, entry = entry_info,
                            }
                        end
                    end
                end
            end
        end
    end

    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _gp_hobj(hand, reg)
            if obj then check_obj(obj, { where = "hand" }) end
        end
    end
    for _, id in ipairs(ctx.current_room.contents or {}) do
        local obj = reg:get(id)
        if obj then
            check_obj(obj, { where = "room" })
            if obj.surfaces then
                for _, zone in pairs(obj.surfaces) do
                    local zone_ok = (zone.accessible ~= false)
                    for _, cid in ipairs(zone.contents or {}) do
                        local item = reg:get(cid)
                        if item then
                            check_obj(item, { where = "surface", parent = obj,
                                surface_accessible = zone_ok })
                        end
                        if item and item.container and item.contents then
                            for _, inner_id in ipairs(item.contents) do
                                local inner = reg:get(inner_id)
                                if inner then
                                    check_obj(inner, { where = "nested",
                                        parent = item, grandparent = obj,
                                        accessible = (item.accessible ~= false),
                                        surface_accessible = zone_ok })
                                end
                            end
                        end
                    end
                end
            end
            if obj.container and obj.contents then
                for _, cid in ipairs(obj.contents) do
                    local item = reg:get(cid)
                    if item then
                        check_obj(item, { where = "container", parent = obj,
                            accessible = (obj.accessible ~= false) })
                    end
                end
            end
        end
    end
    return candidates
end

---------------------------------------------------------------------------
-- Tier 6: Find objects by exact ID across all reachable locations
-- Returns list of { obj, where, parent, ... } entries (same format as find_all)
---------------------------------------------------------------------------
local function find_by_id(ctx, target_id)
    local out = {}
    local reg = ctx.registry
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _gp_hobj(hand, reg)
            if obj and obj.id == target_id then
                out[#out + 1] = { obj = obj, where = "hand" }
            end
            if obj and obj.container and obj.contents then
                for _, cid in ipairs(obj.contents) do
                    local item = reg:get(cid)
                    if item and item.id == target_id then
                        out[#out + 1] = { obj = item, where = "container",
                            parent = obj, accessible = (obj.accessible ~= false) }
                    end
                end
            end
        end
    end
    for _, id in ipairs(ctx.current_room.contents or {}) do
        local obj = reg:get(id)
        if obj and obj.id == target_id then
            out[#out + 1] = { obj = obj, where = "room" }
        end
        if obj and obj.container and obj.contents then
            for _, cid in ipairs(obj.contents) do
                local item = reg:get(cid)
                if item and item.id == target_id then
                    out[#out + 1] = { obj = item, where = "container",
                        parent = obj, accessible = (obj.accessible ~= false) }
                end
            end
        end
        if obj and obj.surfaces then
            for _, zone in pairs(obj.surfaces) do
                local zone_ok = (zone.accessible ~= false)
                for _, cid in ipairs(zone.contents or {}) do
                    local item = reg:get(cid)
                    if item and item.id == target_id then
                        out[#out + 1] = { obj = item, where = "surface",
                            parent = obj, surface_accessible = zone_ok }
                    end
                    if item and item.container and item.contents then
                        for _, inner_id in ipairs(item.contents) do
                            local inner = reg:get(inner_id)
                            if inner and inner.id == target_id then
                                out[#out + 1] = { obj = inner, where = "nested",
                                    parent = item, grandparent = obj,
                                    accessible = (item.accessible ~= false),
                                    surface_accessible = zone_ok }
                            end
                        end
                    end
                end
            end
        end
    end
    return out
end

---------------------------------------------------------------------------
-- Tier 6: Keyword for an object (first keyword or id)
---------------------------------------------------------------------------
local function obj_keyword(obj)
    return obj.keywords and obj.keywords[1] or obj.id
end

---------------------------------------------------------------------------
-- Try to plan fire_source from a single match candidate
---------------------------------------------------------------------------
local function try_plan_match(entry, ctx, visited)
    local m = entry.obj
    if is_spent_or_terminal(m) then return nil end
    local key = m.id .. ":fire"
    if visited[key] then return nil end
    visited[key] = true
    local steps = {}

    -- Already lit — just ensure it's held
    if m._state == "lit" then
        if not is_held(ctx, m.id) then
            steps[#steps + 1] = { verb = "take", noun = "match" }
        end
        return steps
    end

    -- Count spent matches preceding the fresh one in a container.
    -- The take verb grabs the first keyword-matching item, so spent
    -- matches must be removed before the fresh one can be taken.
    local function spent_before_fresh(parent)
        if not parent or not parent.contents then return 0 end
        local count = 0
        for _, cid in ipairs(parent.contents) do
            if cid == m.id then break end
            local item = ctx.registry:get(cid)
            if item and kw_match(item, "match") and is_spent_or_terminal(item) then
                count = count + 1
            end
        end
        return count
    end

    -- Nested match: inside a container that is inside a surface (e.g., matchbox in nightstand)
    if entry.where == "nested" then
        -- Open the grandparent surface if inaccessible (open nightstand drawer)
        if not entry.surface_accessible and entry.grandparent then
            local gn = entry.grandparent.keywords and entry.grandparent.keywords[1]
                or entry.grandparent.id
            steps[#steps + 1] = { verb = "open", noun = gn }
        end
        -- Open the container in place if inaccessible (open matchbox)
        if not entry.accessible and entry.parent then
            local pn = entry.parent.keywords and entry.parent.keywords[1]
                or entry.parent.id
            steps[#steps + 1] = { verb = "open", noun = pn }
        end
        -- Clear spent matches then take the fresh one
        if entry.parent then
            local pn = entry.parent.keywords and entry.parent.keywords[1]
                or entry.parent.id
            for _ = 1, spent_before_fresh(entry.parent) do
                steps[#steps + 1] = { verb = "take", noun = "match from " .. pn }
                steps[#steps + 1] = { verb = "drop", noun = "match" }
            end
            steps[#steps + 1] = { verb = "take", noun = "match from " .. pn }
        end
    elseif entry.where == "container" then
        -- Match in a direct container
        if not entry.accessible and entry.parent then
            local pn = entry.parent.keywords and entry.parent.keywords[1]
                or entry.parent.id
            steps[#steps + 1] = { verb = "open", noun = pn }
        end
        if entry.parent then
            local pn = entry.parent.keywords and entry.parent.keywords[1]
                or entry.parent.id
            -- Clear spent matches then take the fresh one
            for _ = 1, spent_before_fresh(entry.parent) do
                steps[#steps + 1] = { verb = "take", noun = "match from " .. pn }
                steps[#steps + 1] = { verb = "drop", noun = "match" }
            end
            steps[#steps + 1] = { verb = "take", noun = "match from " .. pn }
        else
            steps[#steps + 1] = { verb = "take", noun = "match" }
        end
    elseif entry.where ~= "hand" then
        steps[#steps + 1] = { verb = "take", noun = "match" }
    end

    local striker = find_property(ctx, "has_striker")
    if not striker then return nil end
    local sn = striker.keywords and striker.keywords[1] or striker.id
    steps[#steps + 1] = { verb = "strike", noun = "match on " .. sn }
    return steps
end

---------------------------------------------------------------------------
-- Backward chaining: build steps to obtain fire_source specifically
-- (Preserved from Tier 3 — handles match/striker complexity)
---------------------------------------------------------------------------
local function plan_fire_source(ctx, visited, depth)
    -- Drop any spent/terminal matches from hands
    local spent_drops = {}
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _gp_hobj(hand, ctx.registry)
            if obj and kw_match(obj, "match") and is_spent_or_terminal(obj) then
                spent_drops[#spent_drops + 1] = { verb = "drop", noun = "match" }
            end
        end
    end

    local candidates = find_all(ctx, "match")

    -- Check if any viable candidate needs spent-match container cleanup
    local needs_free_hand = false
    if #spent_drops == 0 and ctx.player.hands[1] and ctx.player.hands[2] then
        for _, entry in ipairs(candidates) do
            if not is_spent_or_terminal(entry.obj)
                and (entry.where == "container" or entry.where == "nested")
                and entry.parent and entry.parent.contents then
                for _, cid in ipairs(entry.parent.contents) do
                    if cid == entry.obj.id then break end
                    local item = ctx.registry:get(cid)
                    if item and kw_match(item, "match") and is_spent_or_terminal(item) then
                        needs_free_hand = true
                        break
                    end
                end
                if needs_free_hand then break end
            end
        end
    end

    -- Free a hand by dropping a non-container held item
    if needs_free_hand then
        for i = 1, 2 do
            local hand = ctx.player.hands[i]
            if hand then
                local obj = _gp_hobj(hand, ctx.registry)
                if obj and not (obj.container and obj.contents) then
                    local n = obj.keywords and obj.keywords[1] or obj.id
                    spent_drops[#spent_drops + 1] = { verb = "drop", noun = n }
                    break
                end
            end
        end
    end

    for _, entry in ipairs(candidates) do
        local result = try_plan_match(entry, ctx, visited)
        if result then
            -- Prepend spent-match drops so the hand slot is free
            for j = #spent_drops, 1, -1 do
                table.insert(result, 1, spent_drops[j])
            end
            return result
        end
    end

    return nil
end

---------------------------------------------------------------------------
-- Tier 6: Plan retrieval steps for an object found at a given location
-- Shared by plan_for_key and plan_generic_tool
---------------------------------------------------------------------------
local function plan_retrieval(entry)
    local steps = {}
    local kn = obj_keyword(entry.obj)

    if entry.where == "nested" then
        if not entry.surface_accessible and entry.grandparent then
            steps[#steps + 1] = { verb = "open", noun = obj_keyword(entry.grandparent) }
        end
        if not entry.accessible and entry.parent then
            steps[#steps + 1] = { verb = "open", noun = obj_keyword(entry.parent) }
        end
        local pn = entry.parent and obj_keyword(entry.parent)
        if pn then
            steps[#steps + 1] = { verb = "take", noun = kn .. " from " .. pn }
        else
            steps[#steps + 1] = { verb = "take", noun = kn }
        end
    elseif entry.where == "container" then
        if not entry.accessible and entry.parent then
            steps[#steps + 1] = { verb = "open", noun = obj_keyword(entry.parent) }
        end
        local pn = entry.parent and obj_keyword(entry.parent)
        if pn then
            steps[#steps + 1] = { verb = "take", noun = kn .. " from " .. pn }
        else
            steps[#steps + 1] = { verb = "take", noun = kn }
        end
    elseif entry.where == "surface" then
        if not entry.surface_accessible and entry.parent then
            steps[#steps + 1] = { verb = "open", noun = obj_keyword(entry.parent) }
        end
        steps[#steps + 1] = { verb = "take", noun = kn }
    elseif entry.where == "room" then
        steps[#steps + 1] = { verb = "take", noun = kn }
    end
    -- "hand" → already held, no retrieval needed
    return steps
end

---------------------------------------------------------------------------
-- Tier 6: Plan to provide light to the room
-- Backward chain: find lightable object → plan its tool requirement
---------------------------------------------------------------------------
local function plan_for_light(ctx, visited, depth)
    if depth > MAX_DEPTH then return nil end
    if presentation and presentation.has_some_light
        and presentation.has_some_light(ctx) then
        return {}
    end

    local cands = find_lightable(ctx)
    for _, cand in ipairs(cands) do
        local vkey = cand.obj.id .. ":light_goal"
        if not visited[vkey] then
            visited[vkey] = true
            local steps = {}

            -- If the lightable object requires a tool, plan for it first
            if cand.transition.requires_tool then
                -- Forward-declare: plan_for_tool is defined below
                local tool_steps = plan_fire_source(ctx, visited, depth + 1)
                if not tool_steps then goto next_light end
                for _, s in ipairs(tool_steps) do steps[#steps + 1] = s end
            end

            -- Add the light step itself
            local kn = obj_keyword(cand.obj)
            steps[#steps + 1] = { verb = "light", noun = kn }
            return steps
        end
        ::next_light::
    end

    return nil
end

---------------------------------------------------------------------------
-- Tier 6: Plan to find and retrieve a specific key (by key_id)
---------------------------------------------------------------------------
local function plan_for_key(key_id, ctx, visited, depth)
    if depth > MAX_DEPTH then return nil end
    local vkey = "key:" .. key_id
    if visited[vkey] then return nil end
    visited[vkey] = true

    -- Already held?
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _gp_hobj(hand, ctx.registry)
            if obj and obj.id == key_id then return {} end
        end
    end

    local entries = find_by_id(ctx, key_id)
    for _, entry in ipairs(entries) do
        if entry.where == "hand" then return {} end
        return plan_retrieval(entry)
    end

    return nil
end

---------------------------------------------------------------------------
-- Tier 6: Generic tool resolution — find any object providing the
-- requested capability, plan retrieval if needed
---------------------------------------------------------------------------
local function plan_generic_tool(capability, ctx, visited, depth)
    if depth > MAX_DEPTH then return nil end
    local reg = ctx.registry

    local function check_provides(obj)
        if not obj then return false end
        local pt = obj.provides_tool
        if pt == capability then return true end
        if type(pt) == "table" then
            for _, c in ipairs(pt) do if c == capability then return true end end
        end
        return false
    end

    -- Search hands first
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _gp_hobj(hand, reg)
            if obj and check_provides(obj) then return {} end
        end
    end

    -- Search room, surfaces, containers
    for _, id in ipairs(ctx.current_room.contents or {}) do
        local obj = reg:get(id)
        if obj and check_provides(obj) then
            return { { verb = "take", noun = obj_keyword(obj) } }
        end
        if obj and obj.surfaces then
            for _, zone in pairs(obj.surfaces) do
                local zone_ok = (zone.accessible ~= false)
                for _, cid in ipairs(zone.contents or {}) do
                    local item = reg:get(cid)
                    if item and check_provides(item) then
                        local steps = {}
                        if not zone_ok then
                            steps[#steps + 1] = { verb = "open", noun = obj_keyword(obj) }
                        end
                        steps[#steps + 1] = { verb = "take", noun = obj_keyword(item) }
                        return steps
                    end
                end
            end
        end
        if obj and obj.container and obj.contents then
            for _, cid in ipairs(obj.contents) do
                local item = reg:get(cid)
                if item and check_provides(item) then
                    local steps = {}
                    if obj.accessible == false then
                        steps[#steps + 1] = { verb = "open", noun = obj_keyword(obj) }
                    end
                    steps[#steps + 1] = { verb = "take",
                        noun = obj_keyword(item) .. " from " .. obj_keyword(obj) }
                    return steps
                end
            end
        end
    end

    return nil
end

---------------------------------------------------------------------------
-- Backward chaining: build steps to obtain a tool capability
-- Tier 6: dispatches to specialized resolvers by capability type
---------------------------------------------------------------------------
local function plan_for_tool(capability, ctx, visited, depth)
    if depth > MAX_DEPTH then return nil end
    if has_tool(ctx, capability) then return {} end
    visited = visited or {}

    -- BUG-090: Safety limit on visited set size to prevent runaway planning
    local visited_count = 0
    for _ in pairs(visited) do visited_count = visited_count + 1 end
    if visited_count > 50 then return nil end

    -- Specialized resolver: fire_source (match/striker chain)
    if capability == "fire_source" then
        return plan_fire_source(ctx, visited, depth)
    end

    -- Generic: find any reachable object providing this capability
    return plan_generic_tool(capability, ctx, visited, depth + 1)
end

---------------------------------------------------------------------------
-- Tier 6: Find locked exit matching noun, return key_id if locked
---------------------------------------------------------------------------
local function find_locked_exit(ctx, noun)
    local room = ctx.current_room
    if not room or not room.exits then return nil end
    local kw = strip_articles(noun)
    for dir, exit in pairs(room.exits) do
        if type(exit) == "table" and exit.locked and exit.key_id then
            -- Match against direction, name, keywords
            if dir:lower() == kw then return exit end
            if exit.name and exit.name:lower():find(kw, 1, true) then return exit end
            if exit.keywords then
                for _, k in ipairs(exit.keywords) do
                    if k:lower() == kw or k:lower():find(kw, 1, true) then
                        return exit
                    end
                end
            end
        end
    end
    return nil
end

---------------------------------------------------------------------------
-- Resolve target object from noun string
---------------------------------------------------------------------------
local function resolve_target(ctx, noun)
    local kw = strip_articles(noun)
    local reg = ctx.registry
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _gp_hobj(hand, reg)
            if obj and kw_match(obj, kw) then return obj end
        end
    end
    for _, id in ipairs(ctx.current_room.contents or {}) do
        local obj = reg:get(id)
        if obj and not obj.hidden and kw_match(obj, kw) then return obj end
        if obj and obj.surfaces then
            for _, zone in pairs(obj.surfaces) do
                if zone.accessible ~= false then
                    for _, cid in ipairs(zone.contents or {}) do
                        local item = reg:get(cid)
                        -- Search inside surface item contents first
                        if item and item.contents then
                            for _, inner_id in ipairs(item.contents) do
                                local inner = reg:get(inner_id)
                                if inner and kw_match(inner, kw) then return inner end
                            end
                        end
                        if item and kw_match(item, kw) then return item end
                    end
                end
            end
        end
    end
    return nil
end

---------------------------------------------------------------------------
-- Public: plan prerequisite steps for verb + noun
-- Tier 6: checks verb-level requirements (light, key) before object-level
-- Returns: list of {verb, noun} steps, or nil if no planning needed/possible
---------------------------------------------------------------------------
function goal_planner.plan(verb, noun, ctx)
    if not noun or noun == "" or not ctx then return nil end

    local canonical = VERB_SYNONYMS[verb] or verb

    -- Tier 6: Verb-level requirement — light
    if LIGHT_VERBS[canonical] then
        if presentation and presentation.has_some_light
            and not presentation.has_some_light(ctx) then
            local steps = plan_for_light(ctx, {}, 0)
            if steps and #steps > 0 then return steps end
        end
    end

    -- Tier 6: Verb-level requirement — unlock needs key
    if canonical == "unlock" then
        local target_word = noun:match("^(.+)%s+with%s+") or noun
        local exit = find_locked_exit(ctx, target_word)
        if exit and exit.key_id then
            local steps = plan_for_key(exit.key_id, ctx, {}, 0)
            if steps and #steps > 0 then return steps end
        end
    end

    -- Object-level: existing prerequisite / FSM tool requirements
    local target_noun = noun:match("^(.-)%s+with%s+") or noun
    local target = resolve_target(ctx, target_noun)
    if not target then return nil end

    -- Check explicit prerequisites table on the object
    local prereqs = target.prerequisites and
        (target.prerequisites[verb] or target.prerequisites[canonical])

    -- Infer from FSM transitions if no explicit prerequisites
    if not prereqs and target.transitions and target._state then
        for _, t in ipairs(target.transitions) do
            if t.from == target._state and t.trigger ~= "auto" then
                local vm = (t.verb == verb) or (t.verb == canonical)
                if not vm and t.aliases then
                    for _, a in ipairs(t.aliases) do
                        if a == verb or a == canonical then vm = true; break end
                    end
                end
                if vm and t.requires_tool then
                    prereqs = { needs_tool = t.requires_tool }
                    break
                end
            end
        end
    end
    if not prereqs then return nil end

    local needed = prereqs.needs_tool or (prereqs.requires and prereqs.requires[1])
    if not needed then return nil end
    return plan_for_tool(needed, ctx, {}, 0)
end

--- Issue #17: Narration templates for GOAP auto-chain steps.
--- Maps verb → function(noun) returning a brief narration prefix.
--- When a verb isn't in the table, the handler's own output suffices.
local STEP_NARRATION = {
    take  = function(noun) return "You look for " .. noun .. "..." end,
    open  = function(noun) return "You need to open " .. noun .. " first." end,
    find  = function(noun) return "You search for " .. noun .. "..." end,
    drop  = function(_)    return nil end,   -- silent helper step
}

--- Execute planned steps through Tier 1 dispatch. Returns true on success.
--- Issue #17: Each step now narrates what's happening so the player sees
--- every intermediate action, not just the final result.
function goal_planner.execute(steps, ctx)
    if not steps or #steps == 0 then return true end
    -- Safety limit: max 7 plan depth → max ~20 individual steps
    if #steps > MAX_PLAN_STEPS then
        print("(That would take too many steps — " .. #steps
            .. " needed, limit is " .. MAX_PLAN_STEPS
            .. ". Try breaking it into simpler steps.)")
        return false
    end
    print("\nYou'll need to prepare first...\n")
    for i, step in ipairs(steps) do
        local handler = ctx.verbs[step.verb]
        if not handler then
            print("(You're not sure how to " .. step.verb .. ".)")
            return false
        end
        -- Issue #17: narrate the step before executing
        local narrator = STEP_NARRATION[step.verb]
        if narrator then
            local msg = narrator(step.noun)
            if msg then print(msg) end
        end
        ctx.current_verb = step.verb
        handler(ctx, step.noun)
    end
    print("")
    return true
end

--- Tier 6: Expose internals for testing
goal_planner._plan_for_light = function(ctx, visited, depth)
    return plan_for_light(ctx, visited or {}, depth or 0)
end
goal_planner._plan_for_key = function(key_id, ctx, visited, depth)
    return plan_for_key(key_id, ctx, visited or {}, depth or 0)
end
goal_planner._plan_for_tool = function(cap, ctx, visited, depth)
    return plan_for_tool(cap, ctx, visited or {}, depth or 0)
end
goal_planner._find_lightable = function(ctx)
    return find_lightable(ctx)
end
goal_planner._find_by_id = function(ctx, id)
    return find_by_id(ctx, id)
end
goal_planner._MAX_DEPTH = MAX_DEPTH

return goal_planner

end

package.preload["engine.parser"] = function()
-- engine/parser/init.lua
-- Tier 2 parser module: wraps the embedding matcher for use in the game loop.
-- Loads the embedding index at startup and exposes a fallback function
-- that the game loop calls when Tier 1 (rule-based verb dispatch) misses.

local embedding_matcher = require("engine.parser.embedding_matcher")

local parser = {}

-- Minimum score to accept a Tier 2 match.
-- Below this threshold, the command fails with diagnostic output.
parser.THRESHOLD = 0.40

---------------------------------------------------------------------------
-- init(assets_root) -> parser instance with matcher loaded
-- assets_root: path to src/assets (e.g., script_dir .. "/assets")
---------------------------------------------------------------------------
function parser.init(assets_root, debug)
  local SEP = package.config:sub(1, 1)
  local index_path = assets_root .. SEP .. "parser" .. SEP .. "embedding-index.json"
  local instance = {
    matcher = embedding_matcher.new(index_path, debug),
    threshold = parser.THRESHOLD,
    diagnostic = debug or false,
  }
  return instance
end

---------------------------------------------------------------------------
-- fallback(instance, input_text, verb_handlers) -> handled (bool)
-- Called by the game loop when Tier 1 has no handler for the parsed verb.
-- If a match is found above threshold AND a verb handler exists, executes it.
-- Returns true if handled, false if the command should fail.
---------------------------------------------------------------------------
function parser.fallback(instance, input_text, context)
  if _G.TRACE then io.stderr:write("[TRACE] embedding_matcher:match entry: " .. tostring(input_text) .. "\n") end
  local verb, noun, score, phrase = instance.matcher:match(input_text)
  if _G.TRACE then io.stderr:write("[TRACE] embedding_matcher:match exit: verb=" .. tostring(verb) .. " noun=" .. tostring(noun) .. " score=" .. tostring(score) .. "\n") end

  if verb and score > instance.threshold then
    local handler = context.verbs[verb]
    if handler then
      context.current_verb = verb
      if _G.TRACE then io.stderr:write("[TRACE] Tier 2 dispatch: " .. verb .. "(" .. tostring(noun) .. ")\n") end
      if instance.diagnostic then
        io.stderr:write(string.format(
          "[Parser] Tier 2 match: \"%s\" → %s %s (score: %.2f, phrase: \"%s\")\n",
          input_text, verb, noun or "", score, phrase or ""
        ))
      end
      handler(context, noun or "")
      if _G.TRACE then io.stderr:write("[TRACE] Tier 2 handler complete: " .. verb .. "\n") end
      return true
    end
  end

  -- Failed: show diagnostic output so Wayne can see what the parser tried
  if instance.diagnostic then
    if verb and phrase then
      print(string.format(
        '[Parser] No match found. Input: "%s" | Best: "%s %s" via "%s" (score: %.2f)',
        input_text, verb, noun or "", phrase, score
      ))
    else
      print(string.format('[Parser] No match found. Input: "%s" | No candidates.', input_text))
    end
  else
    print("I'm not sure what you mean. Try 'help' to see what you can do, or describe what you're trying to accomplish.")
  end

  return false
end

return parser

end

package.preload["engine.parser.json"] = function()
-- engine/parser/json.lua
-- Minimal JSON decoder for loading the embedding index.
-- Supports: objects, arrays, strings, numbers, booleans, null.
-- Not a general-purpose JSON library -- just enough for our index format.

local json = {}

local function skip_ws(s, i)
  return s:match("^%s*()", i)
end

local function decode_string(s, i)
  -- i points at the opening "
  assert(s:sub(i, i) == '"', "expected '\"' at position " .. i)
  local j = i + 1
  local parts = {}
  while j <= #s do
    local c = s:sub(j, j)
    if c == '"' then
      return table.concat(parts), j + 1
    elseif c == '\\' then
      j = j + 1
      local esc = s:sub(j, j)
      if esc == '"' or esc == '\\' or esc == '/' then
        parts[#parts + 1] = esc
      elseif esc == 'n' then parts[#parts + 1] = '\n'
      elseif esc == 'r' then parts[#parts + 1] = '\r'
      elseif esc == 't' then parts[#parts + 1] = '\t'
      elseif esc == 'b' then parts[#parts + 1] = '\b'
      elseif esc == 'f' then parts[#parts + 1] = '\f'
      elseif esc == 'u' then
        -- Basic \uXXXX -- just pass through as-is for ASCII range
        local hex = s:sub(j + 1, j + 4)
        local cp = tonumber(hex, 16)
        if cp and cp < 128 then
          parts[#parts + 1] = string.char(cp)
        else
          parts[#parts + 1] = "?" -- non-ASCII placeholder
        end
        j = j + 4
      end
    else
      parts[#parts + 1] = c
    end
    j = j + 1
  end
  error("unterminated string at position " .. i)
end

local decode_value -- forward declaration

local function decode_array(s, i)
  -- i points at [
  i = skip_ws(s, i + 1)
  local arr = {}
  if s:sub(i, i) == ']' then return arr, i + 1 end
  while true do
    local val
    val, i = decode_value(s, i)
    arr[#arr + 1] = val
    i = skip_ws(s, i)
    local c = s:sub(i, i)
    if c == ']' then return arr, i + 1 end
    assert(c == ',', "expected ',' or ']' at position " .. i)
    i = skip_ws(s, i + 1)
  end
end

local function decode_object(s, i)
  -- i points at {
  i = skip_ws(s, i + 1)
  local obj = {}
  if s:sub(i, i) == '}' then return obj, i + 1 end
  while true do
    local key
    key, i = decode_string(s, i)
    i = skip_ws(s, i)
    assert(s:sub(i, i) == ':', "expected ':' at position " .. i)
    i = skip_ws(s, i + 1)
    local val
    val, i = decode_value(s, i)
    obj[key] = val
    i = skip_ws(s, i)
    local c = s:sub(i, i)
    if c == '}' then return obj, i + 1 end
    assert(c == ',', "expected ',' or '}' at position " .. i)
    i = skip_ws(s, i + 1)
  end
end

decode_value = function(s, i)
  i = skip_ws(s, i)
  local c = s:sub(i, i)
  if c == '"' then return decode_string(s, i)
  elseif c == '{' then return decode_object(s, i)
  elseif c == '[' then return decode_array(s, i)
  elseif c == 't' then
    assert(s:sub(i, i + 3) == 'true')
    return true, i + 4
  elseif c == 'f' then
    assert(s:sub(i, i + 4) == 'false')
    return false, i + 5
  elseif c == 'n' then
    assert(s:sub(i, i + 3) == 'null')
    return nil, i + 4
  else
    -- number
    local num_str = s:match("^-?%d+%.?%d*[eE]?[%+%-]?%d*", i)
    assert(num_str, "unexpected character at position " .. i .. ": '" .. c .. "'")
    return tonumber(num_str), i + #num_str
  end
end

function json.decode(s)
  local val, _ = decode_value(s, 1)
  return val
end

return json

end

package.preload["engine.parser.preprocess"] = function()
-- engine/parser/preprocess.lua
-- Input preprocessing pipeline: natural language normalization and basic parsing.
-- Owned by Smithers (UI Engineer). Pure functions, no side effects.
--
-- Architecture: Table-driven pipeline of composable transform stages.
-- Each stage: string → string (pure transform). Pipeline controls execution order.
-- See docs/architecture/engine/parser/parser-strategy.md for rationale.
--
-- Extracts:
--   preprocess.natural_language(input) -> verb, noun or nil, nil
--   preprocess.parse(input) -> verb, noun
--   preprocess.pipeline -> ordered table of transform stages (externally accessible)

local preprocess = {}

--- Debug flag: when true, prints input→output at each pipeline stage.
preprocess.debug = false

--- strip_articles(noun) -> string
--- Strips leading articles ("the", "a", "an") from a noun phrase (BUG-081).
function preprocess.strip_articles(noun)
    if not noun then return "" end
    return noun:gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
end

--- parse(input) -> verb, noun
--- Splits a raw input string into the first word (verb) and the rest (noun).
--- Handles leading "I" pronoun: "i" is inventory only when typed alone.
function preprocess.parse(input)
    input = input:match("^%s*(.-)%s*$") -- trim
    local verb, noun = input:match("^(%S+)%s*(.*)")
    verb = (verb or ""):lower()
    noun = (noun or ""):lower()
    -- BUG-036: "I" as pronoun, not inventory shortcut. Re-parse the rest.
    if verb == "i" and noun ~= "" then
        return preprocess.parse(noun)
    end
    return verb, noun
end

---------------------------------------------------------------------------
-- BUG-056: Plural-to-singular mapping for noun resolution.
-- Room descriptions use plurals ("torches", "portraits") but objects have
-- singular keywords. Returns a list of candidate singular forms to try.
-- (Defined early so pipeline stages can use it.)
---------------------------------------------------------------------------
local function singularize_word(word)
    if not word or #word < 3 then return {} end
    local forms = {}
    -- -ies → -y (berries → berry, entries → entry)
    local ies_stem = word:match("^(.+)ies$")
    if ies_stem and #ies_stem >= 1 then forms[#forms+1] = ies_stem .. "y" end
    -- -es → strip, only after sibilants: ch, sh, s, x, z
    -- (torches → torch, boxes → box, matches → match)
    local es_stem = word:match("^(.+)es$")
    if es_stem and #es_stem >= 2
        and (es_stem:match("ch$") or es_stem:match("sh$")
             or es_stem:match("[sxz]$")) then
        forms[#forms+1] = es_stem
    end
    -- -s → strip, but not -ss (portraits → portrait, candles → candle)
    local s_stem = word:match("^(.+[^s])s$")
    if s_stem and #s_stem >= 2 then forms[#forms+1] = s_stem end
    return forms
end

---------------------------------------------------------------------------
-- Pipeline Stage Functions
-- Each takes a string, returns a string (primary contract).
-- Convention: stages may return (text, true) as second value to signal
-- they recognized/claimed the input, even if the output text is identical.
-- This lets the pipeline runner distinguish "no match" from "matched but
-- text was already canonical." Pure transforms, no state mutation.
---------------------------------------------------------------------------

--- Stage: normalize
--- Trim whitespace, lowercase, strip trailing question marks.
local function normalize(text)
    if not text or text == "" then return "" end
    local result = text:lower():match("^%s*(.-)%s*$")
    if not result then return "" end
    result = result:gsub("%?+$", "")
    return result
end

--- Stage: strip_politeness
--- Remove politeness prefixes: "please", "kindly", "could you", etc.
local function strip_politeness(text)
    text = text:gsub("^please%s+", "")
    text = text:gsub("^kindly%s+", "")
    text = text:gsub("^could%s+you%s+", "")
    text = text:gsub("^can%s+you%s+", "")
    text = text:gsub("^would%s+you%s+mind%s+", "")
    text = text:gsub("^would%s+you%s+", "")
    text = text:gsub("^will%s+you%s+", "")
    text = text:gsub("^let%s+me%s+", "")
    text = text:gsub("^try%s+to%s+", "")
    text = text:gsub("^attempt%s+to%s+", "")
    text = text:gsub("^i%s+think%s+i'?ll%s+", "")
    text = text:gsub("^maybe%s+i%s+should%s+", "")
    text = text:gsub("^maybe%s+", "")
    text = text:gsub("^perhaps%s+", "")
    return text
end

--- Stage: strip_adverbs (BUG-085)
--- Remove leading and trailing adverbs/modifiers.
local function strip_adverbs(text)
    -- Leading adverbs
    text = text:gsub("^carefully%s+", "")
    text = text:gsub("^closely%s+", "")
    text = text:gsub("^quickly%s+", "")
    text = text:gsub("^slowly%s+", "")
    text = text:gsub("^gently%s+", "")
    text = text:gsub("^thoroughly%s+", "")
    text = text:gsub("^quietly%s+", "")
    text = text:gsub("^frantically%s+", "")
    text = text:gsub("^desperately%s+", "")
    text = text:gsub("^firmly%s+", "")
    text = text:gsub("^softly%s+", "")
    text = text:gsub("^briskly%s+", "")
    text = text:gsub("^hastily%s+", "")
    text = text:gsub("^nervously%s+", "")
    -- Trailing adverbs/modifiers
    text = text:gsub("%s+carefully$", "")
    text = text:gsub("%s+closely$", "")
    text = text:gsub("%s+quickly$", "")
    text = text:gsub("%s+slowly$", "")
    text = text:gsub("%s+gently$", "")
    text = text:gsub("%s+thoroughly$", "")
    text = text:gsub("%s+quietly$", "")
    text = text:gsub("%s+frantically$", "")
    text = text:gsub("%s+desperately$", "")
    text = text:gsub("%s+firmly$", "")
    text = text:gsub("%s+softly$", "")
    text = text:gsub("%s+briskly$", "")
    text = text:gsub("%s+hastily$", "")
    text = text:gsub("%s+nervously$", "")
    text = text:gsub("%s+again$", "")
    -- Guard: don't strip trailing "now" from question phrases ("what now", "where now")
    if not text:match("^wh%w*%s+now$") then
        text = text:gsub("%s+now$", "")
    end
    text = text:gsub("%s+here$", "")
    return text
end

--- Stage: strip_preambles (BUG-036)
--- Iteratively remove "I want to", "I need to", "I'd like to", etc.
--- Iterative (not recursive) — each pass strictly shortens input.
local function strip_preambles(text)
    for _ = 1, 10 do
        local rest = text:match("^i%s+want%s+to%s+know%s+(.+)")
            or text:match("^i%s+want%s+to%s+(.+)")
            or text:match("^i%s+need%s+to%s+know%s+(.+)")
            or text:match("^i%s+need%s+to%s+(.+)")
            or text:match("^i'?d%s+like%s+to%s+know%s+(.+)")
            or text:match("^i'?d%s+like%s+to%s+(.+)")
            or text:match("^i%s+would%s+like%s+to%s+know%s+(.+)")
            or text:match("^i%s+would%s+like%s+to%s+(.+)")
            or text:match("^i'?ll%s+(.+)")
            or text:match("^i%s+need%s+(.+)")
            or text:match("^i%s+want%s+(.+)")
        if not rest then break end
        text = rest
    end
    return text
end

--- Stage: strip_gerunds (BUG-107)
--- Convert a leading gerund verb to its base form after politeness stripping.
--- E.g., "would you mind examining X" → strips to "examining X" → "examine X".
local GERUND_MAP = {
    examining = "examine", looking = "look", searching = "search",
    opening = "open", closing = "close", taking = "take",
    checking = "check", feeling = "feel", reading = "read",
    smelling = "smell", listening = "listen", breaking = "break",
    tasting = "taste", lighting = "light", dropping = "drop",
    wearing = "wear", climbing = "climb", moving = "move",
    pulling = "pull", pushing = "push", finding = "find",
    getting = "get", giving = "give", hiding = "hide",
    picking = "pick", drinking = "drink", eating = "eat",
    using = "use",
}
local function strip_gerunds(text)
    local first, rest = text:match("^(%S+)%s+(.+)$")
    if first and GERUND_MAP[first] then
        return GERUND_MAP[first] .. " " .. rest
    end
    -- Bare gerund with no target
    if GERUND_MAP[text] then
        return GERUND_MAP[text]
    end
    return text
end

--- Stage: strip_filler
--- Iteratively strips preambles, politeness, adverbs, and gerunds until stable.
--- Replaces the recursive natural_language re-entry pattern; single-pass,
--- always terminates (each iteration strictly shortens input or stops).
local function strip_filler(text)
    for _ = 1, 10 do
        local prev = text
        text = strip_preambles(text)
        text = strip_politeness(text)
        text = strip_adverbs(text)
        text = strip_gerunds(text)
        if text == prev then break end
    end
    return text
end

--- Stage: strip_noun_modifiers (Issue #14)
--- Remove quantifier/totality modifiers that players use for emphasis but that
--- confuse noun resolution: "whole", "entire", "every", "all of the", etc.
--- E.g., "search the whole room" → "search the room"
local function strip_noun_modifiers(text)
    -- "all of the X" → "the X"  (must come before single-word strips)
    text = text:gsub("%f[%a]all%s+of%s+the%s+", "the ")
    -- "all of X" → "X"
    text = text:gsub("%f[%a]all%s+of%s+", "")
    -- Single-word modifiers before a noun
    text = text:gsub("%f[%a]whole%s+", "")
    text = text:gsub("%f[%a]entire%s+", "")
    text = text:gsub("%f[%a]every%s+", "")
    -- Collapse any doubled spaces left behind
    text = text:gsub("%s%s+", " ")
    text = text:match("^%s*(.-)%s*$")
    return text
end

---------------------------------------------------------------------------
-- Idiom Library (Tier 3)
-- Table-driven expansion of common English phrases into canonical commands.
-- Each entry: { pattern = Lua pattern, replacement = gsub replacement }.
-- Easy to extend: just append new entries to preprocess.IDIOM_TABLE.
---------------------------------------------------------------------------
local IDIOM_TABLE = {
    { pattern = "^set%s+fire%s+to%s+(.+)$",        replacement = "light %1" },
    { pattern = "^put%s+down%s+(.+)$",              replacement = "drop %1" },
    { pattern = "^blow%s+out%s+(.+)$",              replacement = "extinguish %1" },
    { pattern = "^have%s+a%s+look%s+at%s+(.+)$",    replacement = "examine %1" },
    { pattern = "^take%s+a%s+look%s+at%s+(.+)$",    replacement = "examine %1" },
    { pattern = "^take%s+a%s+peek%s+at%s+(.+)$",    replacement = "examine %1" },
    { pattern = "^have%s+a%s+look%s+around$",        replacement = "look" },
    { pattern = "^take%s+a%s+look%s+around$",        replacement = "look" },
    { pattern = "^have%s+a%s+look$",                replacement = "look" },
    { pattern = "^take%s+a%s+look$",                replacement = "look" },
    { pattern = "^take%s+a%s+peek$",                replacement = "look" },
    { pattern = "^get%s+rid%s+of%s+(.+)$",          replacement = "drop %1" },
    { pattern = "^make%s+use%s+of%s+(.+)$",         replacement = "use %1" },
    { pattern = "^go%s+to%s+sleep$",                replacement = "sleep" },
    { pattern = "^lay%s+down$",                     replacement = "sleep" },
    { pattern = "^lie%s+down$",                     replacement = "sleep" },
    -- #42: "sleep to/til/till dawn" → "sleep until dawn"
    { pattern = "^sleep%s+to%s+(.+)$",             replacement = "sleep until %1" },
    { pattern = "^sleep%s+til%s+(.+)$",            replacement = "sleep until %1" },
    { pattern = "^sleep%s+till%s+(.+)$",           replacement = "sleep until %1" },
}

-- Expose for external extension
preprocess.IDIOM_TABLE = IDIOM_TABLE

--- Stage: expand_idioms
--- Expand common English idioms into canonical game commands.
local function expand_idioms(text)
    for _, idiom in ipairs(IDIOM_TABLE) do
        local new_text = text:gsub(idiom.pattern, idiom.replacement)
        if new_text ~= text then
            return new_text, true
        end
    end
    return text
end

--- Stage: transform_questions
--- Convert question patterns into imperative commands.
local function transform_questions(text)
    -- #38: Hand-specific "what's in my hands" → inventory (BUG-130)
    -- Must come before generic "what's in X" → "examine X" container query
    if text:match("^what'?s%s+in%s+my%s+hands")
        or text:match("^what%s+is%s+in%s+my%s+hands") then
        return "inventory"
    end

    -- "what's in the X" → "examine X"
    local whats_in = text:match("^what'?s%s+in%s+the%s+(.+)$")
        or text:match("^what'?s%s+in%s+(.+)$")
    if whats_in then
        return "examine " .. whats_in
    end

    -- "is there anything in X" → "search X"
    local is_anything_in = text:match("^is%s+there%s+anything%s+in%s+(.+)$")
    if is_anything_in then
        return "search " .. is_anything_in
    end

    -- Issue #23: Existence questions → search
    -- "is there a/an X in the room/here/nearby/around?" → "search X"
    local is_there_in = text:match("^is%s+there%s+an?%s+(.-)%s+in%s+the%s+room$")
        or text:match("^is%s+there%s+an?%s+(.-)%s+here$")
        or text:match("^is%s+there%s+an?%s+(.-)%s+nearby$")
        or text:match("^is%s+there%s+an?%s+(.-)%s+around$")
    if is_there_in then
        return "search " .. is_there_in
    end

    -- "is there a/an X?" → "search X" (bare existence question)
    local is_there_bare = text:match("^is%s+there%s+an?%s+(.+)$")
    if is_there_bare then
        return "search " .. is_there_bare
    end

    -- "do you see a/an X?" → "search X"
    local do_you_see = text:match("^do%s+you%s+see%s+an?%s+(.+)$")
    if do_you_see then
        return "search " .. do_you_see
    end

    -- "can I find a/an X?" → "search X" (specific override before generic "can I verb")
    local can_i_find = text:match("^can%s+i%s+find%s+an?%s+(.+)$")
        or text:match("^can%s+i%s+find%s+(.+)$")
    if can_i_find then
        return "search " .. can_i_find
    end

    -- "can I verb target" → "verb target" (strip question wrapper)
    local can_i_verb, can_i_target = text:match("^can%s+i%s+(%w+)%s+(.+)$")
    if can_i_verb and can_i_target then
        return can_i_verb .. " " .. can_i_target
    end

    -- "what is this" / "what's this" → "look" (BUG-104: "examine this" hung
    -- on unresolved pronoun; "look" is safe without context resolution)
    if text:match("^what%s+is%s+this$") or text:match("^what'?s%s+this$") then
        return "look"
    end

    -- "what can I find" → "search" (BUG-084)
    if text:match("^what%s+can%s+i%s+find") then
        return "search"
    end

    -- "where is the X" → "find X" (BUG-110: "search for X" was interpreted
    -- as scope search on the object rather than searching FOR the object)
    local where_is_target = text:match("^where%s+is%s+the%s+(.+)$")
        or text:match("^where%s+is%s+(.+)$")
        or text:match("^where'?s%s+the%s+(.+)$")
        or text:match("^where'?s%s+(.+)$")
    if where_is_target then
        return "find " .. where_is_target
    end

    -- #36: Bleeding/injury severity questions → injuries
    -- MUST come before "where am I" → look to avoid false match (BUG-128)
    if text:match("^where%s+am%s+i%s+bleeding")
        or text:match("^how%s+bad%s+is%s+it")
        or text:match("^how%s+bad%s+are%s+")
        or text:match("^why%s+don'?t%s+i%s+feel%s+well")
        or text:match("^why%s+don'?t%s+i%s+feel%s+good") then
        return "injuries"
    end

    -- #35: Health/status inquiry phrases → health (BUG-127)
    if text == "status"
        or text:match("^how%s+am%s+i")
        or text:match("^am%s+i%s+hurt")
        or text:match("^am%s+i%s+injured")
        or text:match("^am%s+i%s+ok")
        or text:match("^am%s+i%s+alright")
        or text:match("^what'?s%s+wrong%s+with%s+me")
        or text:match("^what%s+is%s+wrong%s+with%s+me")
        or text:match("^check%s+my%s+wounds")
        or text:match("^check%s+my%s+injuries")
        or text:match("^check%s+my%s+health") then
        return "health"
    end

    -- "what is around" / "what do I see" / "where am I" → "look"
    -- BUG-037: added "what's around me" pattern
    if text:match("^what%s+is%s+around")
        or text:match("^what'?s%s+around")
        or text:match("^what%s+do%s+i%s+see")
        or text:match("^what%s+can%s+i%s+see")
        or text:match("^where%s+am%s+i") then
        return "look"
    end

    -- Question patterns → time
    if text:match("^what%s+time")
        or text:match("^what%s+is%s+the%s+time") then
        return "time"
    end

    -- Question patterns → inventory (BUG-038)
    -- #38: Added hand/holding queries (BUG-130)
    if text:match("^what%s+am%s+i%s+carry")
        or text:match("^what%s+am%s+i%s+hold")
        or text:match("^what%s+do%s+i%s+have")
        or text:match("^what'?s%s+in%s+my%s+hands")
        or text:match("^what%s+is%s+in%s+my%s+hands")
        or text:match("^am%s+i%s+holding%s+anything")
        or text:match("^am%s+i%s+holding%s+something") then
        return "inventory"
    end

    -- Container queries with noun: "what's in X", "what is inside X"
    local container_noun = text:match("^what'?s%s+in%s+(.+)")
        or text:match("^what%s+is%s+in%s+(.+)")
        or text:match("^what'?s%s+inside%s+(.+)")
        or text:match("^what%s+is%s+inside%s+(.+)")
    if container_noun then
        return "examine " .. container_noun
    end

    -- Bare "what's inside" (no noun) → "look"
    if text:match("^what'?s%s+inside$")
        or text:match("^what%s+is%s+inside$") then
        return "look"
    end

    -- Question patterns → help
    if text:match("^what%s+can%s+i%s+do")
        or text:match("^what%s+do%s+i%s+do")
        or text:match("^what%s+should%s+i%s+do")
        or text:match("^what%s+now$")
        or text:match("^now%s+what$")
        or text:match("^how%s+do%s+i") then
        return "help"
    end

    -- "what am I wearing" → "inventory"
    if text:match("^what%s+am%s+i%s+wear") then
        return "inventory"
    end

    return text
end

--- Stage: transform_look_patterns
--- Normalize look/check/look-for into canonical verbs.
local function transform_look_patterns(text)
    -- "look around" → "look" (BUG-037)
    if text:match("^look%s+around$") then
        return "look"
    end

    -- #37: Self-referential look/examine/check → appearance (BUG-129)
    -- Must come before generic "look at X" → "examine X"
    if text:match("^look%s+at%s+myself$")
        or text:match("^look%s+at%s+self$")
        or text:match("^look%s+at%s+me$")
        or text:match("^examine%s+myself$")
        or text:match("^examine%s+self$")
        or text:match("^examine%s+me$")
        or text:match("^check%s+myself$")
        or text:match("^check%s+self$") then
        return "appearance"
    end

    -- #38: "look at my hands" → inventory (BUG-130)
    if text:match("^look%s+at%s+my%s+hands") then
        return "inventory"
    end

    -- BUG-087: "look at X" → "examine X"
    local look_at_target = text:match("^look%s+at%s+(.+)")
    if look_at_target then
        return "examine " .. look_at_target
    end

    -- BUG-086: "check X" → "examine X"
    local check_target = text:match("^check%s+(.+)")
    if check_target then
        return "examine " .. check_target
    end

    -- BUG-118: "peek behind/at/through/in/into/around X" → "examine X"
    -- "peek" (bare) → "look"
    if text == "peek" then
        return "look"
    end
    local peek_target = text:match("^peek%s+behind%s+(.+)")
        or text:match("^peek%s+at%s+(.+)")
        or text:match("^peek%s+through%s+(.+)")
        or text:match("^peek%s+into%s+(.+)")
        or text:match("^peek%s+in%s+(.+)")
        or text:match("^peek%s+around%s+(.+)")
        or text:match("^peek%s+under%s+(.+)")
    if peek_target then
        return "examine " .. peek_target
    end

    -- BUG-112: "look under/underneath/beneath X" → "examine X"
    -- "look under" is not a recognized verb pattern in its own right; without
    -- this transform, the input falls through to Tier 2 search which can hang
    -- on unresolved pronouns. Route to "examine" which safely handles objects.
    local look_under_target = text:match("^look%s+under%s+(.+)")
        or text:match("^look%s+underneath%s+(.+)")
        or text:match("^look%s+beneath%s+(.+)")
    if look_under_target then
        return "examine " .. look_under_target
    end

    -- BUG-074: "look for X" → "find X" (BUG-081: strip articles)
    local look_for_target = text:match("^look%s+for%s+(.+)")
    if look_for_target then
        return "find " .. preprocess.strip_articles(look_for_target)
    end

    return text
end

--- Stage: transform_search_phrases
--- Normalize search/hunt/rummage/find/feel compound phrases.
--- Returns (text, true) on match — some patterns produce identical output
--- (e.g., "search around" is already canonical) but still count as recognized.
---
--- BUG-111: Singularize target nouns so "matches" → "match" for better
--- substring matching against game objects (e.g., "matchbox").
local function singularize_target(noun)
    local forms = singularize_word(noun)
    if #forms > 0 then return forms[1] end
    return noun
end

local function transform_search_phrases(text)
    -- Grope/feel compound phrases → "feel" (room sweep)
    if text:match("^grope%s+around%s+")
        or text:match("^feel%s+around%s+") then
        return "feel", true
    end

    -- "search around" → "search around"
    if text:match("^search%s+around%s*") then
        return "search around", true
    end

    -- "search [scope] for [target]" (BUG-081: strip articles)
    local search_scope_for = text:match("^search%s+(.+)%s+for%s+(.+)")
    if search_scope_for then
        local raw = text:match("^search%s+(.+)$")
        local scope_raw, target_raw = raw:match("^(.-)%s+for%s+(.+)$")
        if scope_raw and target_raw then
            return "search " .. preprocess.strip_articles(scope_raw)
                .. " for " .. preprocess.strip_articles(target_raw), true
        end
        return "search " .. raw, true
    end

    -- "search for [target]" (BUG-081, BUG-078: everything/anything/all → sweep)
    -- BUG-111: singularize target for better fuzzy matching
    local search_target = text:match("^search%s+for%s+(.+)")
    if search_target then
        local stripped = preprocess.strip_articles(search_target)
        if stripped == "everything" or stripped == "anything" or stripped == "all" then
            return "search", true
        end
        return "search " .. singularize_target(stripped), true
    end

    -- "hunt for [target]" / "hunt around" → search (BUG-081, BUG-111)
    local hunt_target = text:match("^hunt%s+for%s+(.+)")
    if hunt_target then
        return "search " .. singularize_target(preprocess.strip_articles(hunt_target)), true
    end
    if text:match("^hunt%s+around%s*") then
        return "search around", true
    end

    -- "rummage" and all forms → search (BUG-081, BUG-093, BUG-111)
    local rummage_target = text:match("^rummage%s+for%s+(.+)")
    if rummage_target then
        return "search " .. singularize_target(preprocess.strip_articles(rummage_target)), true
    end
    local rummage_through = text:match("^rummage%s+through%s+(.+)")
    if rummage_through then
        return "search " .. rummage_through, true
    end
    if text:match("^rummage%s+around%s*") then
        return "search around", true
    end
    if text:match("^rummage$") then
        return "search around", true
    end
    local rummage_scope = text:match("^rummage%s+(.+)")
    if rummage_scope then
        return "search " .. preprocess.strip_articles(rummage_scope), true
    end

    -- "find [target] in [scope]" (BUG-081: strip articles)
    local find_in = text:match("^find%s+(.+)%s+in%s+(.+)")
    if find_in then
        local raw = text:match("^find%s+(.+)$")
        local target_raw, scope_raw = raw:match("^(.-)%s+in%s+(.+)$")
        if target_raw and scope_raw then
            return "find " .. preprocess.strip_articles(target_raw)
                .. " in " .. preprocess.strip_articles(scope_raw), true
        end
        return "find " .. raw, true
    end

    -- "find [target]" (BUG-081, BUG-078: everything/anything/all → sweep, BUG-111)
    local find_target = text:match("^find%s+(.+)")
    if find_target then
        local stripped = preprocess.strip_articles(find_target)
        if stripped == "everything" or stripped == "anything" or stripped == "all" then
            return "search", true
        end
        return "find " .. singularize_target(stripped), true
    end

    return text
end

--- Stage: transform_compound_actions
--- Normalize compound verb phrases (pry open, use X on Y, put/take, etc.)
local function transform_compound_actions(text)
    -- BUG-049: "pry open X" → "open X"
    local pry_target = text:match("^pry%s+open%s+(.+)")
    if pry_target then
        return "open " .. pry_target
    end

    -- "use crowbar/bar on X" → "open X"
    local crowbar_target = text:match("^use%s+crowbar%s+on%s+(.+)")
        or text:match("^use%s+bar%s+on%s+(.+)")
        or text:match("^use%s+pry%s*bar%s+on%s+(.+)")
    if crowbar_target then
        return "open " .. crowbar_target
    end

    -- "report bug" / "report a bug" → "report_bug"
    if text:match("^report%s+a?%s*bug")
        or text:match("^bug%s+report")
        or text:match("^file%s+a?%s*bug") then
        return "report_bug"
    end

    -- "take out X", "pull out X", "yank out X" → "pull X"
    local pull_target = text:match("^take%s+out%s+(.+)")
        or text:match("^pull%s+out%s+(.+)")
        or text:match("^yank%s+out%s+(.+)")
    if pull_target then
        return "pull " .. pull_target
    end

    -- BUG-113: "pick up" (bare, no target) → "take" so loop context fallback kicks in
    if text == "pick up" then
        return "take"
    end

    -- "roll up X" → "move X"
    local roll_target = text:match("^roll%s+up%s+(.+)")
        or text:match("^roll%s+(.+)%s+up$")
    if roll_target then
        return "move " .. roll_target
    end

    -- "pull back X" → "move X"
    local pullback_target = text:match("^pull%s+back%s+(.+)")
    if pullback_target then
        return "move " .. pullback_target
    end

    -- "pop cork" → "uncork bottle"
    local uncork_target = text:match("^pop%s+(.+)")
    if uncork_target and uncork_target:match("cork") then
        return "uncork bottle"
    end

    -- "use X on Y" → dispatch by tool type (BUG-039)
    local use_tool, use_target = text:match("^use%s+(.+)%s+on%s+(.+)$")
    if use_tool and use_target then
        if use_tool:match("needle") or use_tool:match("thread") then
            return "sew " .. use_target .. " with " .. use_tool
        end
        if use_tool:match("key") then
            return "unlock " .. use_target .. " with " .. use_tool
        end
        if use_tool:match("match") or use_tool:match("lighter")
            or use_tool:match("flint") or use_tool:match("torch")
            or use_tool:match("fire") or use_tool:match("flame") then
            return "light " .. use_target .. " with " .. use_tool
        end
        return "put " .. use_tool .. " on " .. use_target
    end

    -- "push X back" → "put X in X"
    local push_back_target = text:match("^push%s+(.+)%s+back")
    if push_back_target then
        return "put " .. push_back_target .. " in " .. push_back_target
    end

    -- "put X back in Y" → "put X in Y"
    local put_back_item, put_back_target2 = text:match("^put%s+(.+)%s+back%s+in%s+(.+)")
    if put_back_item then
        return "put " .. put_back_item .. " in " .. put_back_target2
    end

    -- "put out X", "blow out X" → "extinguish X"
    local extinguish_target = text:match("^put%s+out%s+(.+)")
        or text:match("^blow%s+out%s+(.+)")
    if extinguish_target then
        return "extinguish " .. extinguish_target
    end

    -- "put on X", "dress in X" → "wear X"
    local wear_target = text:match("^put%s+on%s+(.+)")
        or text:match("^dress%s+in%s+(.+)")
    if wear_target then
        return "wear " .. wear_target
    end

    -- "take off X" → "remove X"
    local remove_target = text:match("^take%s+off%s+(.+)")
    if remove_target then
        return "remove " .. remove_target
    end

    return text
end

--- Stage: transform_movement
--- Normalize sleep, stair, clock, and return/go-back phrases.
local function transform_movement(text)
    -- Tier 4: "go back" / "return" → canonical "go back"
    if text == "go back" or text == "go back to where i was" then
        return "go back", true
    end
    if text:match("^go%s+back%s+to%s+") then
        return "go back", true
    end
    if text == "return" then
        return "go back", true
    end
    if text:match("^return%s+to%s+where%s+i%s+was")
        or text:match("^return%s+to%s+the%s+previous%s+room")
        or text:match("^return%s+to%s+previous%s+room") then
        return "go back", true
    end
    if text:match("^retrace%s+my%s+steps") or text:match("^retrace%s+steps") then
        return "go back", true
    end

    -- Sleep phrases
    if text:match("^take%s+a%s+nap") then
        return "sleep"
    end
    local go_sleep_noun = text:match("^go%s+to%s+sleep%s*(.*)")
    if go_sleep_noun then
        if go_sleep_noun == "" then return "sleep" end
        return "sleep " .. go_sleep_noun
    end
    if text:match("^go%s+to%s+bed") then
        return "sleep"
    end
    if text:match("^lie%s+down") then
        return "sleep"
    end

    -- Stair movement
    if text:match("^go%s+down%s+the%s+stair")
        or text:match("^climb%s+down%s+the%s+stair")
        or text:match("^descend%s+the%s+stair")
        or text:match("^descend%s+stair") then
        return "down"
    end
    if text:match("^go%s+up%s+the%s+stair")
        or text:match("^climb%s+up%s+the%s+stair")
        or text:match("^ascend%s+the%s+stair")
        or text:match("^ascend%s+stair") then
        return "up"
    end

    -- Clock adjustment: "turn hands", "adjust clock", "set clock"
    local clock_target = text:match("^turn%s+hands%s*(.*)$")
        or text:match("^turn%s+the%s+hands%s*(.*)$")
    if clock_target then
        local target = clock_target ~= "" and clock_target or "clock"
        return "set " .. target
    end
    if text:match("^adjust%s+the%s+clock") or text:match("^adjust%s+clock") then
        return "set clock"
    end
    if text:match("^set%s+the%s+clock") or text:match("^set%s+clock") then
        return "set clock"
    end

    return text
end

---------------------------------------------------------------------------
-- Pipeline Definition
-- Ordered table of transform stages. Externally accessible for extension.
-- Adding a new stage: table.insert(preprocess.pipeline, N, my_transform)
-- Disabling a stage: table.remove(preprocess.pipeline, N)
---------------------------------------------------------------------------

preprocess.pipeline = {
    normalize,                -- Trim, lowercase, strip question marks
    strip_filler,             -- Iterative: preambles + politeness + adverbs
    strip_noun_modifiers,     -- Issue #14: whole/entire/every/all-of-the
    expand_idioms,            -- Tier 3: common English phrases → canonical commands
    transform_questions,      -- Question patterns → imperative commands
    transform_look_patterns,  -- look at/for/around, check → canonical verbs
    transform_search_phrases, -- search/hunt/rummage/find compounds
    transform_compound_actions, -- pry, use X on Y, put/take, pull, wear
    transform_movement,       -- sleep, stairs, clock, go back/return
}

-- Expose individual stage functions for testing and reuse
preprocess.stages = {
    normalize = normalize,
    strip_politeness = strip_politeness,
    strip_adverbs = strip_adverbs,
    strip_preambles = strip_preambles,
    strip_gerunds = strip_gerunds,
    strip_filler = strip_filler,
    strip_noun_modifiers = strip_noun_modifiers,
    expand_idioms = expand_idioms,
    transform_questions = transform_questions,
    transform_look_patterns = transform_look_patterns,
    transform_search_phrases = transform_search_phrases,
    transform_compound_actions = transform_compound_actions,
    transform_movement = transform_movement,
}

--- natural_language(input) -> verb, noun or nil, nil
--- Runs the preprocessing pipeline, then parses the result.
--- Returns nil, nil if no transform matched (caller should fall through to parse).
function preprocess.natural_language(input, _depth)
    -- _depth accepted for backward compatibility but unused (pipeline is iterative)
    if not input then return nil, nil end

    local text = input
    local matched = false
    for i, transform in ipairs(preprocess.pipeline) do
        local before = text
        local result, stage_matched = transform(text)
        text = result
        if stage_matched or text ~= before then
            matched = true
        end
        if preprocess.debug and (stage_matched or text ~= before) then
            print(string.format("  [pipeline %d] %q → %q%s",
                i, before, text, stage_matched and " (claimed)" or ""))
        end
    end

    if text == "" then return nil, nil end

    -- If any stage transformed or recognized the text, parse the result
    local original = normalize(input)
    if matched or text ~= original then
        return preprocess.parse(text)
    end

    return nil, nil
end


--- split_commands(input) -> list of command strings
--- Splits a raw input line on commas, semicolons, or the word "then" to support
--- multi-command input (e.g. "move bed, move rug, open trapdoor").
--- Trims whitespace from each segment and drops empty segments.
--- Does NOT split on separators inside double-quoted text.
function preprocess.split_commands(input)
    if not input then return {} end
    local trimmed = input:match("^%s*(.-)%s*$")
    if trimmed == "" then return {} end

    -- Fast path: no separators at all → single command
    if not trimmed:find("[,;]") and not trimmed:lower():find("%f[%a]then%f[%A]") then
        return { trimmed }
    end

    -- Tokenise respecting double-quoted regions
    local segments = {}
    local current = {}
    local in_quote = false
    local lower = trimmed:lower()
    local i = 1
    local len = #trimmed

    while i <= len do
        local ch = trimmed:sub(i, i)

        -- Toggle quote state
        if ch == '"' then
            in_quote = not in_quote
            current[#current + 1] = ch
            i = i + 1

        -- Comma or semicolon separator (outside quotes)
        elseif not in_quote and (ch == ',' or ch == ';') then
            local seg = table.concat(current):match("^%s*(.-)%s*$")
            if seg ~= "" then segments[#segments + 1] = seg end
            current = {}
            i = i + 1

        -- " then " word separator (outside quotes)
        elseif not in_quote and lower:sub(i, i + 5) == " then " then
            local seg = table.concat(current):match("^%s*(.-)%s*$")
            if seg ~= "" then segments[#segments + 1] = seg end
            current = {}
            i = i + 6  -- skip " then "

        else
            current[#current + 1] = ch
            i = i + 1
        end
    end

    -- Flush last segment
    local seg = table.concat(current):match("^%s*(.-)%s*$")
    if seg ~= "" then segments[#segments + 1] = seg end

    -- If splitting produced nothing useful, return original as single command
    if #segments == 0 then return { trimmed } end
    return segments
end

--- singularize(noun) -> table of singular form candidates
--- For multi-word nouns, also tries singularizing the last word.
function preprocess.singularize(noun)
    if not noun or #noun < 3 then return {} end
    noun = noun:lower()
    local forms = singularize_word(noun)
    -- Multi-word: also try singularizing just the last word
    local prefix, last = noun:match("^(.+%s)(%S+)$")
    if prefix then
        for _, s in ipairs(singularize_word(last)) do
            forms[#forms+1] = prefix .. s
        end
    end
    return forms
end

return preprocess

end

package.preload["engine.player.appearance"] = function()
-- engine/player/appearance.lua
-- Player appearance subsystem: reads player state and composes a natural
-- language description for mirrors, "look at self", and future multiplayer.
-- Pure read → compose → return pipeline. Never modifies player state.
--
-- Ownership: Smithers (UI Engineer)

local appearance = {}

---------------------------------------------------------------------------
-- Helpers
---------------------------------------------------------------------------

--- Combine phrases into natural English with Oxford comma.
--- Deduplicates identical phrases (Issue #31: duplicate bruise text).
local function compose_natural(phrases)
    -- Deduplicate identical phrases
    local seen = {}
    local unique = {}
    for _, p in ipairs(phrases) do
        if not seen[p] then
            seen[p] = true
            unique[#unique + 1] = p
        end
    end
    phrases = unique

    if #phrases == 0 then return nil end
    if #phrases == 1 then return phrases[1] end
    if #phrases == 2 then return phrases[1] .. " and " .. phrases[2] end
    local last = table.remove(phrases)
    return table.concat(phrases, ", ") .. ", and " .. last
end

--- Get injuries at specific body locations.
local function get_injuries_at(player, locations)
    local matches = {}
    for _, injury in ipairs(player.injuries or {}) do
        if injury.location then
            local loc_lower = injury.location:lower()
            for _, pattern in ipairs(locations) do
                if loc_lower:find(pattern:lower(), 1, true) then
                    matches[#matches + 1] = injury
                    break
                end
            end
        end
    end
    return matches
end

--- Severity → adjective mapping.
local severity_adjectives = {
    minor    = { "small", "slight" },
    moderate = { "deep", "nasty" },
    severe   = { "grievous", "terrible" },
}

local function pick_severity_adjective(severity)
    local options = severity_adjectives[severity]
    if not options then return nil end
    return options[math.random(#options)]
end

--- Compose a natural injury phrase from structured data.
local function render_injury_phrase(injury)
    local adj = pick_severity_adjective(injury.severity)

    -- Determine injury noun based on type
    local noun_map = {
        bleeding = "gash",
        bruised  = "bruise",
        concussion = "bruise",
        burn     = "burn",
    }
    local noun = noun_map[injury.type] or "wound"

    local phrase = adj and (adj .. " " .. noun) or noun

    if injury.location then
        phrase = phrase .. " on your " .. injury.location
    end

    -- Treatment check
    if injury._state == "treated" or injury.treatment then
        phrase = phrase .. ", wrapped in a bandage"
    end

    return "a " .. phrase
end

--- Resolve object from ID or table.
local function resolve_obj(item, registry)
    if type(item) == "table" then return item end
    if type(item) == "string" and registry then
        local get = registry.get
        if get then return registry:get(item) end
    end
    return nil
end

---------------------------------------------------------------------------
-- Layer renderers
---------------------------------------------------------------------------

local function render_head(player, registry)
    local parts = {}

    -- Worn headgear
    if player.worn then
        for _, worn_id in ipairs(player.worn) do
            local obj = resolve_obj(worn_id, registry)
            if obj and (obj.wear_slot == "head" or obj.is_helmet) then
                if obj.appearance and obj.appearance.worn_description then
                    parts[#parts + 1] = obj.appearance.worn_description
                else
                    parts[#parts + 1] = (obj.name or "a helmet") .. " sits on your head"
                end
            end
        end
    end

    -- Head injuries
    local head_injuries = get_injuries_at(player, {"head", "face", "forehead", "scalp"})
    for _, injury in ipairs(head_injuries) do
        parts[#parts + 1] = render_injury_phrase(injury)
    end

    if #parts == 0 then return nil end
    return compose_natural(parts)
end

local function render_torso(player, registry)
    local parts = {}

    -- Worn torso armor/clothing
    if player.worn then
        for _, worn_id in ipairs(player.worn) do
            local obj = resolve_obj(worn_id, registry)
            if obj and obj.wear_slot == "torso" then
                if obj.appearance and obj.appearance.worn_description then
                    parts[#parts + 1] = obj.appearance.worn_description
                else
                    parts[#parts + 1] = "you are wearing " .. (obj.name or "something") .. " on your torso"
                end
            end
        end
    end

    -- Torso injuries
    local torso_injuries = get_injuries_at(player, {"torso", "chest", "ribs", "stomach", "side"})
    for _, injury in ipairs(torso_injuries) do
        parts[#parts + 1] = render_injury_phrase(injury)
    end

    if #parts == 0 then return nil end
    return compose_natural(parts)
end

local function render_arms(player, registry)
    local parts = {}

    -- Arm injuries
    local arm_injuries = get_injuries_at(player, {"left arm", "right arm", "arm"})
    for _, injury in ipairs(arm_injuries) do
        parts[#parts + 1] = render_injury_phrase(injury)
    end

    if #parts == 0 then return nil end
    return compose_natural(parts)
end

local function render_hands(player, registry)
    local parts = {}
    local hand_names = { "left", "right" }

    -- Held items
    for i, hand_slot in ipairs(player.hands or {}) do
        if hand_slot then
            local obj = resolve_obj(hand_slot, registry)
            if obj then
                parts[#parts + 1] = "your " .. hand_names[i] .. " hand grips " .. (obj.name or "something")
            else
                parts[#parts + 1] = "your " .. hand_names[i] .. " hand grips something"
            end
        end
    end

    -- Hand injuries
    local hand_injuries = get_injuries_at(player, {"hand", "fingers", "wrist"})
    for _, injury in ipairs(hand_injuries) do
        parts[#parts + 1] = render_injury_phrase(injury)
    end

    if #parts == 0 then return nil end
    return compose_natural(parts)
end

local function render_legs(player, registry)
    local parts = {}

    -- Leg injuries
    local leg_injuries = get_injuries_at(player, {"left leg", "right leg", "leg"})
    for _, injury in ipairs(leg_injuries) do
        parts[#parts + 1] = render_injury_phrase(injury)
    end

    if #parts == 0 then return nil end
    return compose_natural(parts)
end

local function render_feet(player, registry)
    local parts = {}

    -- Worn footwear
    if player.worn then
        for _, worn_id in ipairs(player.worn) do
            local obj = resolve_obj(worn_id, registry)
            if obj and obj.wear_slot == "feet" then
                if obj.appearance and obj.appearance.worn_description then
                    parts[#parts + 1] = obj.appearance.worn_description
                else
                    parts[#parts + 1] = (obj.name or "boots") .. " cover your feet"
                end
            end
        end
    end

    if #parts == 0 then return nil end
    return compose_natural(parts)
end

local function render_overall(player)
    local parts = {}

    -- Health-based pallor
    local inj_ok, injury_mod = pcall(require, "engine.injuries")
    local health = player.max_health or 100
    if inj_ok and injury_mod then
        health = injury_mod.compute_health(player)
    end
    local pct = health / (player.max_health or 100)

    if pct <= 0.25 then
        parts[#parts + 1] = "your skin is deathly pale, eyes sunken"
    elseif pct <= 0.50 then
        parts[#parts + 1] = "you look pale and unsteady"
    elseif pct <= 0.75 then
        parts[#parts + 1] = "you look a bit worn but standing"
    end

    -- Global blood state
    if player.state and player.state.bloody then
        parts[#parts + 1] = "dried blood is visible on your skin and clothes"
    end

    if #parts == 0 then return nil end
    return compose_natural(parts)
end

---------------------------------------------------------------------------
-- Main API
---------------------------------------------------------------------------

--- Compose a natural language description of a player's appearance.
--- @param player table — player state table (hands, worn, injuries, max_health)
--- @param registry table|nil — object registry for resolving IDs
--- @return string — composed description (multi-sentence, natural English)
function appearance.describe(player, registry)
    -- Guard: unconscious player can't see their reflection
    if player.consciousness
       and (player.consciousness.state == "unconscious"
         or player.consciousness.state == "waking") then
        return "You can't examine yourself — you're unconscious."
    end

    local layers = {
        render_head,
        render_torso,
        render_arms,
        render_hands,
        render_legs,
        render_feet,
    }

    local phrases = {}
    for _, renderer in ipairs(layers) do
        local phrase = renderer(player, registry)
        if phrase then
            phrases[#phrases + 1] = phrase
        end
    end

    -- Overall health (separate — it's a summary, not a body part)
    local overall = render_overall(player)
    if overall then
        phrases[#phrases + 1] = overall
    end

    if #phrases == 0 then
        return "Your reflection shows an unremarkable figure in plain clothes, unharmed and unburdened."
    end

    -- Capitalize first letter of composed description
    local desc = table.concat(phrases, ". ")
    -- Issue #30: Capitalize first letter after every ". " separator
    desc = desc:gsub("%.%s+(%l)", function(c) return ". " .. c:upper() end)
    desc = desc:sub(1, 1):upper() .. desc:sub(2)
    if not desc:match("[%.!?]$") then desc = desc .. "." end

    return "In the mirror, you see: " .. desc
end

---------------------------------------------------------------------------
-- Test exports
---------------------------------------------------------------------------
appearance._render_head = render_head
appearance._render_torso = render_torso
appearance._render_arms = render_arms
appearance._render_hands = render_hands
appearance._render_legs = render_legs
appearance._render_feet = render_feet
appearance._render_overall = render_overall
appearance._get_injuries_at = get_injuries_at
appearance._render_injury_phrase = render_injury_phrase
appearance._compose_natural = compose_natural

return appearance

end

package.preload["engine.registry"] = function()
-- engine/registry/init.lua
-- The universe's object store: id -> live object table.
-- Every live object in a universe is registered here.
-- Supports weight tracking and category-based queries.

local registry = {}
registry.__index = registry

-- normalize_guid(guid) -> string
-- Strips braces from GUIDs to handle both "{abc-123}" and "abc-123" formats.
local function normalize_guid(guid)
  if type(guid) ~= "string" then return guid end
  return guid:gsub("^%{(.-)%}$", "%1")
end

-- new() -> registry instance
function registry.new()
  return setmetatable({ _objects = {}, _guid_index = {} }, registry)
end

-- register(id, object) -- adds or replaces an object; stamps the id onto the object.
-- Also indexes by guid if the object has one.
function registry:register(id, object)
  assert(type(id) == "string" and id ~= "", "registry: id must be a non-empty string")
  assert(type(object) == "table", "registry: object must be a table")
  object.id = id
  self._objects[id] = object
  if type(object.guid) == "string" and object.guid ~= "" then
    self._guid_index[normalize_guid(object.guid)] = id
  end
end

-- get(id) -> object | nil
function registry:get(id)
  return self._objects[id]
end

-- find_by_guid(guid) -> object | nil
-- Looks up an object by its definition guid using the guid index.
function registry:find_by_guid(guid)
  local id = self._guid_index[normalize_guid(guid)]
  if id then return self._objects[id] end
  return nil
end

-- remove(id) -> removed object | nil
function registry:remove(id)
  local obj = self._objects[id]
  if obj and type(obj.guid) == "string" then
    self._guid_index[normalize_guid(obj.guid)] = nil
  end
  self._objects[id] = nil
  return obj
end

-- list() -> array of all live objects (order undefined)
function registry:list()
  local result = {}
  for _, obj in pairs(self._objects) do
    result[#result + 1] = obj
  end
  return result
end

-- find_by_keyword(keyword) -> first matching object | nil
-- Matches against object.keywords (array of strings) and object.name.
-- BUG-056: also tries singular forms of plural nouns.
function registry:find_by_keyword(keyword)
  local preprocess = require("engine.parser.preprocess")
  local kw = keyword:lower()
  local candidates = { kw }
  for _, s in ipairs(preprocess.singularize(kw)) do
    candidates[#candidates + 1] = s
  end
  for _, try_kw in ipairs(candidates) do
    for _, obj in pairs(self._objects) do
      if obj.name and obj.name:lower() == try_kw then
        return obj
      end
      if type(obj.keywords) == "table" then
        for _, k in ipairs(obj.keywords) do
          if k:lower() == try_kw then return obj end
        end
      end
    end
  end
  return nil
end

-- find_by_category(category) -> array of matching objects
-- Returns all objects that have the given category in their categories list.
function registry:find_by_category(category)
  local result = {}
  local cat = category:lower()
  for _, obj in pairs(self._objects) do
    if type(obj.categories) == "table" then
      for _, c in ipairs(obj.categories) do
        if c:lower() == cat then
          result[#result + 1] = obj
          break
        end
      end
    end
  end
  return result
end

-- total_weight(location_id) -> number
-- Sums the weight of all objects at a given location.
-- Useful for room weight limits or structural checks.
function registry:total_weight(location_id)
  local total = 0
  for _, obj in pairs(self._objects) do
    if obj.location == location_id then
      total = total + (obj.weight or 0)
    end
  end
  return total
end

-- contents_weight(container_id, surface_name) -> number
-- Sums the weight of all objects inside a container (or a specific surface).
function registry:contents_weight(container_id, surface_name)
  local container_obj = self._objects[container_id]
  if not container_obj then return 0 end

  local contents = {}
  if surface_name and container_obj.surfaces and container_obj.surfaces[surface_name] then
    contents = container_obj.surfaces[surface_name].contents or {}
  else
    contents = container_obj.contents or {}
  end

  local total = 0
  for _, item_id in ipairs(contents) do
    local obj = self._objects[item_id]
    if obj then
      total = total + (obj.weight or 0)
    end
  end
  return total
end

return registry

end

