        end
    end
    
    -- BUG-075: Then expand nested containers (recursive) when doing a scoped search
    if include_nested_containers and containers.is_container(obj) then
        -- Get the sub-containers (e.g., drawers inside nightstand)
        local contents = containers.get_contents(obj, registry)
        for _, child_id in ipairs(contents) do
            local child = registry:get(child_id)
            if child and containers.is_container(child) then
                -- Recursively expand nested containers
                local child_entries = expand_object(child_id, registry, depth + 1, include_nested_containers, visited)
                for _, child_entry in ipairs(child_entries) do
                    entries[#entries + 1] = child_entry
                end
            end
        end
    end
    
    return entries
end

--- Build a search queue from room proximity list
-- @param room room object
-- @param scope object ID or nil
-- @param target search target or nil
-- @param registry registry instance
-- @return ordered list of queue entries
function traverse.build_queue(room, scope, target, registry)
    local queue = {}
    
    -- Get proximity-ordered object list
    local proximity_list = traverse.get_proximity_list(room)
    
    -- If scope provided, filter to just that object
    local search_list = proximity_list
    local include_nested_containers = false
    if scope then
        search_list = {}
        for _, obj_id in ipairs(proximity_list) do
            if obj_id == scope then
                search_list[#search_list + 1] = obj_id
                -- BUG-075: When searching a specific object, include nested containers
                include_nested_containers = true
                break
            end
        end
        -- BUG-082: If scope not found in proximity list, check parts of room objects
        -- This handles sub-components (e.g., "drawer" is a part of nightstand)
        if #search_list == 0 and registry then
            for _, obj_id in ipairs(proximity_list) do
                local obj = registry:get(obj_id)
                if obj and obj.parts then
                    for part_key, part in pairs(obj.parts) do
                        if part.id == scope or part_key == scope then
                            -- Use the parent object but with nested containers enabled
                            search_list[#search_list + 1] = obj_id
                            include_nested_containers = true
                            break
                        end
                    end
                    if #search_list > 0 then break end
                end
            end
        end
    end
    
    -- Expand each object into searchable entries
    for _, obj_id in ipairs(search_list) do
        local entries = expand_object(obj_id, registry, 0, include_nested_containers)
        for _, entry in ipairs(entries) do
            queue[#queue + 1] = entry
        end
    end
    
    return queue
end

---------------------------------------------------------------------------
-- Process one step of traversal
---------------------------------------------------------------------------

--- Check if object matches target (fuzzy matching)
-- @param object object instance
-- @param target string
-- @param registry registry instance
-- @param depth number (recursion depth tracking)
-- @return boolean
local function matches_target(object, target, registry, depth, visited)
    depth = depth or 0
    visited = visited or {}
    
    if not object or not target then
        return false
    end

    -- Spatial visibility: hidden objects never match (#26)
    if object.hidden then
        return false
    end

    -- Cycle detection: skip objects already checked in this match walk.
    -- Prevents infinite recursion from circular containment references.
    local oid = object.id
    if oid and visited[oid] then
        return false
    end
    if oid then
        visited[oid] = true
    end

    -- Secondary safety belt: depth limit matches containment model depth
    if depth > 3 then
        return false
    end
    
    target = target:lower()
    -- BUG-081: Strip articles from target before matching
    target = target:gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
    
    -- Exact ID match
    if object.id and object.id:lower() == target then
        return true
    end
    
    -- Exact name match
    if object.name and object.name:lower() == target then
        return true
    end
    
    -- Substring match in name
    if object.name and object.name:lower():find(target, 1, true) then
        return true
    end
    
    -- Keyword match
    if object.keywords then
        for _, kw in ipairs(object.keywords) do
            if kw:lower() == target or kw:lower():find(target, 1, true) then
                return true
            end
        end
    end
    
    -- If object is container, check contents recursively (fuzzy)
    if containers.is_container(object) and containers.is_open(object) then
        local contents = containers.get_contents(object, registry)
        for _, child_id in ipairs(contents) do
            local child = registry:get(child_id)
            if child and matches_target(child, target, registry, depth + 1, visited) then
                return true
            end
        end
    end
    
    return false
end

--- Peek inside a matched container for a more specific match (#22)
-- When search finds a container whose name matches the target (e.g., "matchbox"
-- matches "match"), peek inside to see if contents match more directly.
-- Read-only: never mutates state (D-PEEK).
-- @param obj container object that matched the target
-- @param target string search target
-- @param registry registry instance
-- @return child object if a deeper match is found, nil otherwise
local function find_deeper_match(obj, target, registry)
    if not containers.is_container(obj) then return nil end
    local contents = containers.get_contents(obj, registry)
    for _, child_id in ipairs(contents) do
        local child = registry:get(child_id)
        if child and matches_target(child, target, registry, 0) then
            return child
        end
    end
    return nil
end

--- Process one step of traversal
-- @param ctx game context
-- @param entry queue entry
-- @param target what we're looking for
-- @param is_goal_search boolean
-- @param goal_type string
-- @param goal_value string
-- @return result table {found: boolean, item: object or nil, continue: boolean, narrative: string}
function traverse.step(ctx, entry, target, is_goal_search, goal_type, goal_value)
    local registry = ctx.registry
    local room = ctx.current_room
    
    local result = {
        found = false,
        item = nil,
        continue = true,
        narrative = "",
    }
    
    -- BUG-075: Handle surface entries (e.g., nightstand's "inside" surface = drawer)
    if entry.type == "surface" and entry.parent_id and entry.surface_name then
        local parent = registry:get(entry.parent_id)
        if not parent then
            result.narrative = ""
            return result
        end
        
        -- Get current state's surfaces template (for accessibility check)
        -- But use parent's actual surfaces for contents (where items are)
        local surface_template = parent.surfaces and parent.surfaces[entry.surface_name]
        if parent._state and parent.states and parent.states[parent._state] then
            local state_obj = parent.states[parent._state]
            if state_obj.surfaces and state_obj.surfaces[entry.surface_name] then
                surface_template = state_obj.surfaces[entry.surface_name]
            end
        end
        
        -- Check if surface exists
        if not surface_template then
            result.narrative = ""
            return result
        end
        
        -- If surface is not accessible, peek without changing state (#24)
        if surface_template.accessible == false then
            -- Check if parent is locked (via FSM state or container flag)
            local is_locked = containers.is_locked(parent)
            if is_locked then
                result.narrative = narrator.container_locked(ctx, parent)
                return result
            end

            -- Only peek inside container surfaces (drawers, wardrobes, etc.)
            -- Non-container inaccessible surfaces (e.g., rug's "underneath")
            -- are truly hidden and can't be searched until made accessible (#26)
            if not containers.is_container(parent) then
                result.narrative = ""
                return result
            end
            
            -- Peek at contents without opening (#24: read-only search)
            local actual_surface = parent.surfaces and parent.surfaces[entry.surface_name]
            local contents = actual_surface and actual_surface.contents or {}
            
            -- Undirected search: enumerate contents
            if not target and not is_goal_search then
                if #contents > 0 then
                    local items = {}
                    for _, child_id in ipairs(contents) do
                        local child = registry:get(child_id)
                        if child then
                            items[#items + 1] = child.name or child.id
                        end
                    end
                    result.narrative = narrator.container_contents_no_target(ctx, parent, items, nil)
                else
                    result.narrative = narrator.container_contents_no_target(ctx, parent, {}, nil)
                end
                return result
            end
            
            -- Targeted search: check contents for match, report what's there if not found (#27)
            for _, child_id in ipairs(contents) do
                local child = registry:get(child_id)
                if child then
                    if target and not is_goal_search then
                        if matches_target(child, target, registry, 0) then
                            -- #22: If matched child is a container, peek inside for a more specific match
                            local deeper = find_deeper_match(child, target, registry)
                            if deeper then
                                result.found = true
                                result.item = deeper
                                result.narrative = narrator.container_peek(ctx, parent) .. "\n" .. narrator.container_peek(ctx, child) .. "\n" .. narrator.found_target(ctx, deeper, child)
                            else
                                result.found = true
                                result.item = child
                                result.narrative = narrator.container_peek(ctx, parent) .. "\n" .. narrator.found_target(ctx, child, parent)
                            end
                            return result
                        end
                    elseif is_goal_search and goal_type and goal_value then
                        if goals.matches_goal(child, goal_type, goal_value, registry) then
                            result.found = true
                            result.item = child
                            result.narrative = narrator.container_peek(ctx, parent) .. "\n" .. narrator.found_target(ctx, child, parent)
                            return result
                        end
                    end
                end
            end
            
            -- Target not found inside — report what IS there (#27)
            if target then
                local items = {}
                for _, child_id in ipairs(contents) do
                    local child = registry:get(child_id)
                    if child then
                        items[#items + 1] = child.name or child.id
                    end
                end
                result.narrative = narrator.container_contents_no_target(ctx, parent, items, target)
            end
            return result
        end
        
        -- Now surface is accessible - check its contents
        -- ALWAYS use parent.surfaces for contents (not state template)
        local actual_surface = parent.surfaces and parent.surfaces[entry.surface_name]
        local contents = actual_surface and actual_surface.contents or {}

        -- BUG-079: Undirected scoped search should enumerate surface contents
        if not target and not is_goal_search and #contents > 0 then
            local items = {}
            for _, child_id in ipairs(contents) do
                local child = registry:get(child_id)
                if child then
                    items[#items + 1] = child.name or child.id
                end
            end
            if #items > 0 then
                result.narrative = (result.narrative ~= "" and result.narrative .. "\n" or "")
                    .. "Inside you find: " .. table.concat(items, ", ") .. "."
            end
            return result
        end

        for _, child_id in ipairs(contents) do
            local child = registry:get(child_id)
            if child then
                -- Check if child matches target
                if target and not is_goal_search then
                    if matches_target(child, target, registry, 0) then
                        result.found = true
                        result.item = child
                        result.narrative = result.narrative .. "\n" .. narrator.found_target(ctx, child, parent)
                        return result
                    end
                elseif is_goal_search and goal_type and goal_value then
                    if goals.matches_goal(child, goal_type, goal_value, registry) then
                        result.found = true
                        result.item = child
                        result.narrative = result.narrative .. "\n" .. narrator.found_target(ctx, child, parent)
                        return result
                    end
                end
            end
        end
        
        -- BUG-126 (#34): Target not found in accessible surface — report what IS there (#27)
        if target and #contents > 0 then
            local items = {}
            for _, child_id in ipairs(contents) do
                local child = registry:get(child_id)
                if child then
                    items[#items + 1] = child.name or child.id
                end
            end
            if #items > 0 then
                result.narrative = narrator.container_contents_no_target(ctx, parent, items, target)
            end
        end

        -- Surface checked, no match found
        return result
    end
    
    -- Get the object (for non-surface entries)
    local obj = registry:get(entry.object_id)
    if not obj then
        result.narrative = ""
        return result
    end
    
    -- #40: Objects with surfaces have their contents searched via surface entries
    -- in the queue. Skip the object entry to avoid contradictory narration
    -- (e.g., "nothing there" followed by surface entry reporting contents).
    -- For targeted searches, still check if the object itself matches the target.
    if obj.surfaces then
        if target and not is_goal_search then
            if matches_target(obj, target, registry, 0) then
                result.found = true
                result.item = obj
                result.narrative = narrator.found_target(ctx, obj, nil)
                return result
            end
        elseif is_goal_search and goal_type and goal_value then
            if goals.matches_goal(obj, goal_type, goal_value, registry) then
                result.found = true
                result.item = obj
                result.narrative = narrator.found_target(ctx, obj, nil)
                return result
            end
        end
        -- No match or undirected — suppress narration; surfaces follow in queue
        result.narrative = ""
        return result
    end

    -- If it's a container and it's closed, peek without opening (#24)
    if entry.is_container and not entry.is_open then
        if entry.is_locked then
            -- Locked - skip with note
            result.narrative = narrator.container_locked(ctx, obj)
            return result
        else
            -- Peek at contents without changing state (#24: read-only search)
            local contents = containers.get_contents(obj, registry)

            -- BUG-079: Undirected scoped search should enumerate container contents
            if not target and not is_goal_search then
                if #contents > 0 then
                    local items = {}
                    for _, child_id in ipairs(contents) do
                        local child = registry:get(child_id)
                        if child then
                            items[#items + 1] = child.name or child.id
                        end
                    end
                    result.narrative = narrator.container_contents_no_target(ctx, obj, items, nil)
                else
                    result.narrative = narrator.container_contents_no_target(ctx, obj, {}, nil)
                end
                return result
            end

            -- Targeted search: check contents, report what's there if not found (#27)
            for _, child_id in ipairs(contents) do
                local child = registry:get(child_id)
                if child then
                    if target and not is_goal_search then
                        if matches_target(child, target, registry, 0) then
                            -- #22: If matched child is a container, peek inside for a more specific match
                            local deeper = find_deeper_match(child, target, registry)
                            if deeper then
                                result.found = true
                                result.item = deeper
                                result.narrative = narrator.container_peek(ctx, obj) .. "\n" .. narrator.container_peek(ctx, child) .. "\n" .. narrator.found_target(ctx, deeper, child)
                            else
                                result.found = true
                                result.item = child
                                result.narrative = narrator.container_peek(ctx, obj) .. "\n" .. narrator.found_target(ctx, child, obj)
                            end
                            return result
                        end
                    elseif is_goal_search and goal_type and goal_value then
                        if goals.matches_goal(child, goal_type, goal_value, registry) then
                            result.found = true
                            result.item = child
                            result.narrative = narrator.container_peek(ctx, obj) .. "\n" .. narrator.found_target(ctx, child, obj)
                            return result
                        end
                    end
                end
            end

            -- Target not found inside — check if the container itself matches (#22)
            if target and not is_goal_search then
                if matches_target(obj, target, registry, 0) then
                    result.found = true
                    result.item = obj
                    result.narrative = narrator.container_peek(ctx, obj) .. "\n" .. narrator.found_target(ctx, obj, nil)
                    return result
                end
            end

            -- Target not found inside or on container — report what IS there (#27)
            if target then
                local items = {}
                for _, child_id in ipairs(contents) do
                    local child = registry:get(child_id)
                    if child then
                        items[#items + 1] = child.name or child.id
                    end
                end
                result.narrative = narrator.container_contents_no_target(ctx, obj, items, target)
            end
            return result
        end
    end
    
    -- #34: Handle open container objects — check contents, report what's inside
    if entry.is_container and entry.is_open then
        local contents = containers.get_contents(obj, registry)
        
        -- Undirected search: enumerate contents
        if not target and not is_goal_search then
            if #contents > 0 then
                local items = {}
                for _, child_id in ipairs(contents) do
                    local child = registry:get(child_id)
                    if child then
                        items[#items + 1] = child.name or child.id
                    end
                end
                result.narrative = narrator.container_contents_no_target(ctx, obj, items, nil)
            else
                result.narrative = narrator.step_narrative(ctx, obj, false)
            end
            return result
        end
        
        -- Targeted search: check contents for match
        for _, child_id in ipairs(contents) do
            local child = registry:get(child_id)
            if child then
                if target and not is_goal_search then
                    if matches_target(child, target, registry, 0) then
                        local deeper = find_deeper_match(child, target, registry)
                        if deeper then
                            result.found = true
                            result.item = deeper
                            result.narrative = narrator.container_peek(ctx, child) .. "\n" .. narrator.found_target(ctx, deeper, child)
                        else
                            result.found = true
                            result.item = child
                            result.narrative = narrator.found_target(ctx, child, obj)
                        end
                        return result
                    end
                elseif is_goal_search and goal_type and goal_value then
                    if goals.matches_goal(child, goal_type, goal_value, registry) then
                        result.found = true
                        result.item = child
                        result.narrative = narrator.found_target(ctx, child, obj)
                        return result
                    end
                end
            end
        end
        
        -- Target not found in contents — check if the container itself matches (#22)
        if target and not is_goal_search then
            if matches_target(obj, target, registry, 0) then
                result.found = true
                result.item = obj
                result.narrative = narrator.found_target(ctx, obj, nil)
                return result
            end
        end

        -- Target not found inside or on container — report what IS there (#34)
        if target and #contents > 0 then
            local items = {}
            for _, child_id in ipairs(contents) do
                local child = registry:get(child_id)
                if child then
                    items[#items + 1] = child.name or child.id
                end
            end
            result.narrative = narrator.container_contents_no_target(ctx, obj, items, target)
        else
            result.narrative = narrator.step_narrative(ctx, obj, false)
        end
        return result
    end
    
    -- Check if this object matches the target
    if target and not is_goal_search then
        if matches_target(obj, target, registry, 0) then
            -- #22: If matched object is a container, peek inside for a more specific match
            local deeper = find_deeper_match(obj, target, registry)
            if deeper then
                result.found = true
                result.item = deeper
                result.narrative = narrator.container_peek(ctx, obj) .. "\n" .. narrator.found_target(ctx, deeper, obj)
            else
                result.found = true
                result.item = obj
                result.narrative = narrator.found_target(ctx, obj, nil)
            end
            return result
        end
    elseif is_goal_search and goal_type and goal_value then
        if goals.matches_goal(obj, goal_type, goal_value, registry) then
            result.found = true
            result.item = obj
            result.narrative = narrator.found_target(ctx, obj, nil)
            return result
        end
    end
    
    -- Not found - generate step narrative
    result.narrative = narrator.step_narrative(ctx, obj, false)
    return result
end

return traverse

end

package.preload["engine.traverse_effects"] = function()
-- engine/traverse_effects.lua
-- Extensible on_traverse exit-effect engine.
--
-- When a player moves through an exit, the engine checks for an optional
-- on_traverse table on that exit. If present, it dispatches to a registered
-- handler based on the effect's `type` field.
--
-- Ownership: Bart (Architect)
-- Decision: D-TRAVERSE001 — on_traverse exit-effect pattern
--
-- Usage in room metadata:
--   exits = {
--     up = {
--       target = "storage-cellar",
--       on_traverse = {
--         type = "wind_effect",
--         description = "A cold draft rushes up the stairway...",
--         extinguishes = { "candle" }
--       }
--     }
--   }

local traverse_effects = {}

-- Registry of effect handlers keyed by type string.
-- Each handler: function(effect, ctx) -> nil
-- Handlers print their own messages and mutate state via ctx.
local handlers = {}

--- Register a new on_traverse effect handler.
-- @param effect_type  string   The `type` value that triggers this handler.
-- @param handler_fn   function(effect, ctx)  Called when the effect fires.
function traverse_effects.register(effect_type, handler_fn)
    handlers[effect_type] = handler_fn
end

--- Normalize an on_traverse table into { type = ..., ...fields }.
-- Accepts two formats:
--   1. Flat:   { type = "wind_effect", extinguishes = {...}, ... }
--   2. Nested: { wind_effect = { extinguishes = {...}, ... } }
-- Returns the normalized effect table, or nil if unrecognized.
local function normalize_effect(raw)
    if raw.type then return raw end

    -- Nested format: single key whose value is the effect payload
    local effect_type, payload
    for k, v in pairs(raw) do
        if type(v) == "table" then
            if effect_type then return nil end  -- ambiguous: multiple keys
            effect_type = k
            payload = v
        end
    end
    if not effect_type then return nil end

    -- Merge into flat format expected by handlers
    local flat = { type = effect_type }
    for k, v in pairs(payload) do flat[k] = v end
    return flat
end

--- Process an exit's on_traverse effects, if any.
-- Called by the movement handler BEFORE the player is moved.
-- @param exit  table|string  The exit definition from room metadata.
-- @param ctx   table         The game context (registry, player, etc.)
function traverse_effects.process(exit, ctx)
    if type(exit) ~= "table" then return end
    local raw = exit.on_traverse
    if not raw then return end

    local effect = normalize_effect(raw)
    if not effect then return end

    local handler = handlers[effect.type]
    if not handler then return end

    handler(effect, ctx)
end

---------------------------------------------------------------------------
-- Built-in handler: wind_effect
--
-- Checks player inventory for items in the `extinguishes` list.
-- If a matching item is found AND is in a "lit" state AND is NOT
-- wind_resistant, transitions it to "extinguished" (or "unlit") state.
---------------------------------------------------------------------------
local function wind_effect_handler(effect, ctx)
    local fsm_mod = require("engine.fsm")
    local presentation = require("engine.ui.presentation")

    local carried_ids = presentation.get_all_carried_ids(ctx)
    local extinguish_set = {}
    for _, name in ipairs(effect.extinguishes or {}) do
        extinguish_set[name:lower()] = true
    end

    local something_extinguished = false
    local something_spared = false

    for _, obj_id in ipairs(carried_ids) do
        local obj = ctx.registry:get(obj_id)
        if obj then
            -- Check if this object is in the extinguishes list (by id or keywords)
            local targeted = false
            if obj.id and extinguish_set[obj.id:lower()] then
                targeted = true
            end
            if not targeted and type(obj.keywords) == "table" then
                for _, kw in ipairs(obj.keywords) do
                    if extinguish_set[kw:lower()] then
                        targeted = true
                        break
                    end
                end
            end

            if targeted and obj._state == "lit" then
                if obj.wind_resistant then
                    something_spared = true
                else
                    -- Try extinguished first, then unlit
                    local trans, err = fsm_mod.transition(
                        ctx.registry, obj_id, "extinguished", nil, "extinguish"
                    )
                    if not trans then
                        trans, err = fsm_mod.transition(
                            ctx.registry, obj_id, "unlit", nil, "extinguish"
                        )
                    end
                    if trans then
                        something_extinguished = true
                    end
                end
            elseif not targeted and obj._state == "lit" and obj.wind_resistant then
                -- Not in extinguish list but lit and wind-resistant — spared
                something_spared = true
            end
        end
    end

    -- Print messages: effect description first, then outcome
    if something_extinguished or something_spared then
        if effect.description then
            print(effect.description)
        end
    end
    if something_extinguished then
        print(effect.message_extinguish or "The draft snuffs out your flame!")
    end
    if something_spared and not something_extinguished then
        if effect.message_spared then
            print(effect.message_spared)
        end
    end
end

traverse_effects.register("wind_effect", wind_effect_handler)

return traverse_effects

end

package.preload["engine.ui"] = function()
-- engine/ui/init.lua
-- Split-screen terminal UI using ANSI escape codes.
--
-- Layout (H = terminal height):
--   Line 1        : Status bar (reverse video)
--   Lines 2..H-2  : Output window (scrollable history)
--   Line H-1      : Delimiter (dashes)
--   Line H        : Input line ("> " prompt)
--
-- Pure Lua + ANSI. No external C libs.  Windows 10+ compatible.
-- Falls back to plain print/read when ANSI is unavailable.

local ui = {}

---------------------------------------------------------------------------
-- ANSI helpers
---------------------------------------------------------------------------
local ESC = "\27"

local function csi(...)  return ESC .. "[" .. table.concat({...}) end
local function move_to(r, c) io.write(csi(r, ";", c or 1, "H")) end
local function clear_eol()   io.write(csi("K")) end
local function hide_cursor() io.write(csi("?25l")) end
local function show_cursor() io.write(csi("?25h")) end
local function reverse()     io.write(csi("7m")) end
local function reset_attr()  io.write(csi("0m")) end
local function clear_screen()io.write(csi("2J")) end
local function set_scroll_region(top, bot)
    io.write(csi(top, ";", bot, "r"))
end
local function reset_scroll_region() io.write(csi("r")) end

---------------------------------------------------------------------------
-- State (module-level, single instance)
---------------------------------------------------------------------------
local enabled      = false
local width        = 80
local height       = 24
local buffer       = {}     -- scrollback: array of wrapped lines
local max_buffer   = 500
local scroll_off   = 0     -- 0 = viewing bottom; positive = scrolled up
local stat_left    = ""
local stat_right   = ""

-- Computed geometry (set by compute_regions)
local out_top, out_bot, out_lines
local delim_row, input_row

local function compute_regions()
    out_top    = 2
    out_bot    = height - 2
    out_lines  = out_bot - out_top + 1
    delim_row  = height - 1
    input_row  = height
end

---------------------------------------------------------------------------
-- Terminal size detection
---------------------------------------------------------------------------
local function detect_size()
    local w, h = 80, 24
    if package.config:sub(1, 1) == "\\" then
        -- Windows: parse "mode con" output
        local ok, p = pcall(io.popen, "mode con 2>nul")
        if ok and p then
            local out = p:read("*a")
            p:close()
            local cols  = out:match("Columns:%s*(%d+)")
            local lines = out:match("Lines:%s*(%d+)")
            if cols  then w = tonumber(cols)  end
            if lines then h = tonumber(lines) end
        end
    else
        local ok, p = pcall(io.popen, "stty size 2>/dev/null")
        if ok and p then
            local out = p:read("*l")
            p:close()
            if out then
                local r, c = out:match("(%d+)%s+(%d+)")
                if r then h = tonumber(r) end
                if c then w = tonumber(c) end
            end
        end
    end
    return w, h
end

---------------------------------------------------------------------------
-- Word-wrap (replicates display.word_wrap logic for buffer lines)
---------------------------------------------------------------------------
local function wrap_text(text, w)
    w = w or width
    if not text then return { "" } end
    if text == "" then return { "" } end

    local lines = {}
    for segment in (text .. "\n"):gmatch("(.-)\n") do
        if segment == "" then
            lines[#lines + 1] = ""
        elseif #segment <= w then
            lines[#lines + 1] = segment
        else
            local indent = segment:match("^(%s*)") or ""
            local content = segment:sub(#indent + 1)
            local line = indent
            for word in content:gmatch("%S+") do
                if line == indent then
                    line = indent .. word
                elseif #line + 1 + #word > w then
                    lines[#lines + 1] = line
                    line = indent .. word
                else
                    line = line .. " " .. word
                end
            end
            if line ~= indent or line ~= "" then
                lines[#lines + 1] = line
            end
        end
    end
    -- gmatch artifact: trailing empty string from appended "\n"
    if #lines > 1 and lines[#lines] == "" and not text:match("\n$") then
        table.remove(lines)
    end
    if #lines == 0 then lines = { "" } end
    return lines
end

---------------------------------------------------------------------------
-- Drawing primitives
---------------------------------------------------------------------------

local function draw_status()
    move_to(1, 1)
    reverse()
    local left  = stat_left  or ""
    local right = stat_right or ""
    local pad   = width - #left - #right
    if pad < 1 then pad = 1 end
    local bar = left .. string.rep(" ", pad) .. right
    if #bar > width then bar = bar:sub(1, width) end
    io.write(bar)
    reset_attr()
end

local function draw_delimiter()
    move_to(delim_row, 1)
    clear_eol()
    io.write(string.rep("-", width))
end

local function redraw_output()
    local total   = #buffer
    local visible = out_lines
    local start_idx = total - visible - scroll_off + 1
    if start_idx < 1 then start_idx = 1 end

    for i = 0, visible - 1 do
        local buf_idx = start_idx + i
        local row     = out_top + i
        move_to(row, 1)
        clear_eol()
        if buf_idx >= 1 and buf_idx <= total then
            local line = buffer[buf_idx] or ""
            if #line > width then line = line:sub(1, width) end
            io.write(line)
        end
    end
end

local function draw_input_prompt(text)
    move_to(input_row, 1)
    clear_eol()
    io.write("> " .. (text or ""))
end

local function full_refresh()
    hide_cursor()
    draw_status()
    redraw_output()
    draw_delimiter()
    draw_input_prompt("")
    show_cursor()
    io.flush()
end

---------------------------------------------------------------------------
-- Buffer management
---------------------------------------------------------------------------
local function append_to_buffer(text)
    local lines = wrap_text(text, width)
    for _, line in ipairs(lines) do
        buffer[#buffer + 1] = line
        if #buffer > max_buffer then
            table.remove(buffer, 1)
            if scroll_off > 0 then scroll_off = scroll_off - 1 end
        end
    end
end

---------------------------------------------------------------------------
-- Public API
---------------------------------------------------------------------------

--- Initialise the split-screen UI.  Returns true on success.
function ui.init()
    width, height = detect_size()
    if height < 8 or width < 20 then
        -- Terminal too small for split-screen
        return false
    end

    compute_regions()
    buffer     = {}
    scroll_off = 0
    stat_left  = ""
    stat_right = ""
    enabled    = true

    -- Enable VT processing on Windows (harmless no-op if already active)
    if package.config:sub(1, 1) == "\\" then
        os.execute("")
    end

    clear_screen()
    -- Set scroll region to output area so Enter on input line won't scroll
    set_scroll_region(out_top, out_bot)
    full_refresh()
    return true
end

function ui.is_enabled()
    return enabled
end

function ui.get_width()
    return width
end

--- Print text into the output window (replaces raw print when UI is active).
function ui.output(text)
    if not enabled then
        io.write((text or "") .. "\n")
        io.flush()
        return
    end

    append_to_buffer(text or "")
    scroll_off = 0  -- snap to bottom on new output

    hide_cursor()
    redraw_output()
    show_cursor()
    io.flush()
end

--- Update the status bar.
function ui.status(left, right)
    stat_left  = left  or stat_left
    stat_right = right or stat_right
    if not enabled then return end
    hide_cursor()
    draw_status()
    show_cursor()
    io.flush()
end

--- Read one line from the input area.
--- Returns nil on EOF.
function ui.input()
    if not enabled then
        io.write("> ")
        io.flush()
        return io.read()
    end

    -- Position cursor at input line
    move_to(input_row, 1)
    clear_eol()
    io.write("> ")
    show_cursor()
    io.flush()

    local text = io.read()
    if not text then return nil end

    -- Immediately clear the input line to prevent stale echo
    move_to(input_row, 1)
    clear_eol()
    io.flush()

    return text
end

--- Sub-prompt (e.g., "What do you want to write? > ").
--- Shows msg in the output window, then reads from input line.
function ui.prompt(msg)
    if not enabled then
        io.write(msg)
        io.flush()
        return io.read()
    end

    ui.output(msg)
    return ui.input()
end

--- Scroll the output window up by n lines (default ≈ one page).
function ui.scroll_up(n)
    if not enabled then return end
    n = n or math.max(1, out_lines - 2)
    local max_scroll = math.max(0, #buffer - out_lines)
    scroll_off = math.min(scroll_off + n, max_scroll)
    hide_cursor()
    redraw_output()
    show_cursor()
    io.flush()
end

--- Scroll the output window down by n lines (default ≈ one page).
function ui.scroll_down(n)
    if not enabled then return end
    n = n or math.max(1, out_lines - 2)
    scroll_off = math.max(0, scroll_off - n)
    hide_cursor()
    redraw_output()
    show_cursor()
    io.flush()
end

--- Returns true (and handles it) if input is a scroll command.
function ui.handle_scroll(input)
    if not enabled then return false end
    local cmd = (input or ""):match("^%s*(.-)%s*$")
    if cmd == "/up" or cmd == "/pgup" then
        ui.scroll_up()
        return true
    elseif cmd == "/down" or cmd == "/pgdn" then
        ui.scroll_down()
        return true
    elseif cmd == "/bottom" then
        scroll_off = 0
        hide_cursor()
        redraw_output()
        show_cursor()
        io.flush()
        return true
    end
    return false
end

--- Full-screen refresh (status + output + delimiter + input prompt).
function ui.refresh()
    if not enabled then return end
    full_refresh()
end

--- Restore terminal to normal state.
function ui.cleanup()
    if not enabled then return end
    enabled = false
    reset_scroll_region()
    reset_attr()
    show_cursor()
    clear_screen()
    move_to(1, 1)
    io.flush()
end

return ui

end

package.preload["engine.ui.presentation"] = function()
-- engine/ui/presentation.lua
-- Presentation helpers: time formatting, light level, vision checks.
-- Owned by Smithers (UI Engineer). These read game state to produce
-- display-ready values. No mutations — pure queries.
--
-- Shared constants (single source of truth for time calculations):
--   GAME_SECONDS_PER_REAL_SECOND, GAME_START_HOUR, DAYTIME_START, DAYTIME_END

local presentation = {}

---------------------------------------------------------------------------
-- Constants (authoritative — remove duplicates from verbs/init.lua, main.lua)
---------------------------------------------------------------------------
presentation.GAME_SECONDS_PER_REAL_SECOND = 24
presentation.GAME_START_HOUR = 2
presentation.DAYTIME_START = 6
presentation.DAYTIME_END = 18

---------------------------------------------------------------------------
-- Carried items utility (needed by get_light_level)
---------------------------------------------------------------------------

--- Returns flat list of all object IDs the player is carrying
--- (hands + held bag contents + worn items + worn bag contents)
function presentation.get_all_carried_ids(ctx)
    local ids = {}
    local reg = ctx.registry
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local hand_id = type(hand) == "table" and hand.id or hand
            ids[#ids + 1] = hand_id
            local obj = type(hand) == "table" and hand or reg:get(hand)
            if obj and obj.container and obj.contents then
                for _, item_id in ipairs(obj.contents) do
                    ids[#ids + 1] = item_id
                end
            end
        end
    end
    for _, worn_id in ipairs(ctx.player.worn or {}) do
        ids[#ids + 1] = worn_id
        local obj = reg:get(worn_id)
        if obj and obj.container and obj.contents then
            for _, item_id in ipairs(obj.contents) do
                ids[#ids + 1] = item_id
            end
        end
    end
    return ids
end

---------------------------------------------------------------------------
-- Time
---------------------------------------------------------------------------

--- Returns game hour and minute from real-time clock.
function presentation.get_game_time(ctx)
    local real_elapsed = os.time() - ctx.game_start_time
    local total_game_hours = (real_elapsed * presentation.GAME_SECONDS_PER_REAL_SECOND) / 3600
    local absolute_hour = presentation.GAME_START_HOUR + total_game_hours + (ctx.time_offset or 0)
    local hour = math.floor(absolute_hour % 24)
    local minute = math.floor((absolute_hour * 60) % 60)
    return hour, minute
end

--- Returns true if the game clock is between DAYTIME_START and DAYTIME_END.
function presentation.is_daytime(ctx)
    local hour = presentation.get_game_time(ctx)
    return hour >= presentation.DAYTIME_START and hour < presentation.DAYTIME_END
end

--- Formats hour+minute into "H:MM AM/PM".
function presentation.format_time(hour, minute)
    local period = hour >= 12 and "PM" or "AM"
    local display_hour = hour % 12
    if display_hour == 0 then display_hour = 12 end
    return string.format("%d:%02d %s", display_hour, minute, period)
end

--- Returns a prose description of the time of day.
function presentation.time_of_day_desc(hour)
    if hour >= 5 and hour < 7 then return "Dawn breaks on the horizon."
    elseif hour >= 7 and hour < 10 then return "Morning light fills the sky."
    elseif hour >= 10 and hour < 14 then return "The sun stands high overhead."
    elseif hour >= 14 and hour < 17 then return "The afternoon sun angles westward."
    elseif hour >= 17 and hour < 19 then return "Dusk gathers at the edges of the world."
    elseif hour >= 19 and hour < 21 then return "Night has fallen."
    else return "Deep night. The world sleeps."
    end
end

---------------------------------------------------------------------------
-- Light system — tri-state: "lit", "dim", "dark"
--   "lit"  = full light (open curtains + daytime, or artificial light)
--   "dim"  = filtered daylight through closed curtains during daytime
--   "dark" = no light at all (nighttime, no candle)
-- Dim light is enough to see and interact; descriptions note the dimness.
---------------------------------------------------------------------------

function presentation.get_light_level(ctx)
    local room = ctx.current_room
    local reg = ctx.registry

    -- Artificial light always gives full "lit" (candle, torch, etc.)
    for _, obj_id in ipairs(room.contents or {}) do
        local obj = reg:get(obj_id)
        if obj and obj.casts_light then return "lit" end
        if obj and obj.surfaces then
            for _, zone in pairs(obj.surfaces) do
                for _, item_id in ipairs(zone.contents or {}) do
                    local item = reg:get(item_id)
                    -- Check contents of surface items (e.g., candle inside holder)
                    if item and item.contents then
                        for _, inner_id in ipairs(item.contents) do
                            local inner = reg:get(inner_id)
                            if inner and inner.casts_light then return "lit" end
                        end
                    end
                    if item and item.casts_light then return "lit" end
                end
            end
        end
    end
    for _, obj_id in ipairs(presentation.get_all_carried_ids(ctx)) do
        local obj = reg:get(obj_id)
        if obj and obj.casts_light then return "lit" end
    end

    -- Daylight: open curtains = "lit", closed curtains = "dim"
    if presentation.is_daytime(ctx) then
        local has_filter = false
        for _, obj_id in ipairs(room.contents or {}) do
            local obj = reg:get(obj_id)
            if obj and obj.allows_daylight then return "lit" end
            if obj and obj.filters_daylight then has_filter = true end
        end
        if has_filter then return "dim" end
    end

    return "dark"
end

--- Convenience: can the player see enough to interact?
function presentation.has_some_light(ctx)
    return presentation.get_light_level(ctx) ~= "dark"
end

---------------------------------------------------------------------------
-- Vision check
---------------------------------------------------------------------------

--- Returns true, blocker_obj if player's vision is blocked by a worn item.
function presentation.vision_blocked_by_worn(ctx)
    local reg = ctx.registry
    for _, worn_id in ipairs(ctx.player.worn or {}) do
        local obj = reg:get(worn_id)
        if obj and obj.wear and obj.wear.blocks_vision then
            return true, obj
        end
    end
    return false, nil
end

return presentation

end

